async function bootAuth(){
  await cdjEnsureSupabaseSession();
  // Restaurar sessão se houver
  const session = sbGetSession();
  if(session?.user && session?.access_token){
    currentUser = session.user;
    try {
      const prof = await fetchProfile(session.user.id);
      if(prof.ativo){
        currentProfile = prof;
        enterApp(prof);
        return;
      }
    } catch(e) {
      // Sessão expirada ou perfil sumiu — limpa
      sbSignOut();
    }
  }
  // Mostrar login
  const ls = document.getElementById('login-screen');
  if(ls) ls.style.display = 'flex';
}

function setDbStatus(ok, msg){
  // Safe: elements may not be visible yet
  const dot = document.getElementById('db-dot');
  const lbl = document.getElementById('db-label');
  if(dot) dot.className = ok ? 'db-dot' : 'db-dot off';
  if(lbl) lbl.textContent = msg;
}

function initDB(){
  return new Promise((res, rej)=>{
    try{
      const req = indexedDB.open('MarquesSpanJornada', 7);
      req.onupgradeneeded = e=>{
        const dbObj = e.target.result;
        if(!dbObj.objectStoreNames.contains('actions'))
          dbObj.createObjectStore('actions',{keyPath:'id',autoIncrement:true});
        if(!dbObj.objectStoreNames.contains('sessions'))
          dbObj.createObjectStore('sessions',{keyPath:'id',autoIncrement:true});
        if(!dbObj.objectStoreNames.contains('phones'))
          dbObj.createObjectStore('phones',{keyPath:'nome'});
        if(!dbObj.objectStoreNames.contains('weeks'))
          dbObj.createObjectStore('weeks',{keyPath:'id'});
        // v7: store dedicado para snapshots DIÁRIOS (separado de 'weeks').
        // Estrutura: {id:'dia_AAAAMMDD', tipo:'DIA', data_ref, datas[], rows[],
        //             actions[], salvo_em, supabase_id?, salvo_nuvem:bool, iso_year, iso_week}
        if(!dbObj.objectStoreNames.contains('daily_analyses'))
          dbObj.createObjectStore('daily_analyses',{keyPath:'id'});
        if(!dbObj.objectStoreNames.contains('cadastros'))
          dbObj.createObjectStore('cadastros',{keyPath:'type'}); // keys: motoristas/auxiliares/veiculos/cidades
      };
      req.onsuccess = e=>{
        db = e.target.result;
        // Status com contagem de registros
        updateDbStatusDetailed();
        res(db);
      };
      req.onerror = e=>{
        console.warn('IndexedDB error:', e.target.error);
        setDbStatus(false, 'Usando localStorage (sem banco local)');
        res(null); // resolve (not reject) so app continues
      };
      req.onblocked = ()=>{
        console.warn('IndexedDB blocked — another tab may be open');
        setDbStatus(false, 'IndexedDB bloqueado — feche outras abas');
        res(null);
      };
    }catch(e){
      console.warn('IndexedDB not available:', e);
      setDbStatus(false, 'Usando localStorage');
      res(null);
    }
  });
}

function dbGetAll(store){
  return new Promise((res,rej)=>{
    if(!db){res(lsGet('actions_'+store,[]));return;}
    const tx=db.transaction(store,'readonly');
    const req=tx.objectStore(store).getAll();
    req.onsuccess=()=>res(req.result);
    req.onerror=()=>res([]);
  });
}
function dbAdd(store,obj){
  return new Promise((res,rej)=>{
    if(!db){const a=lsGet('actions_'+store,[]);a.push({...obj,id:Date.now()});lsSet('actions_'+store,a);res();return;}
    const tx=db.transaction(store,'readwrite');
    tx.objectStore(store).add(obj);
    tx.oncomplete=()=>res();
    tx.onerror=()=>rej();
  });
}
function dbDelete(store,id){
  return new Promise((res,rej)=>{
    if(!db){const a=lsGet('actions_'+store,[]).filter(x=>x.id!==id);lsSet('actions_'+store,a);res();return;}
    const tx=db.transaction(store,'readwrite');
    tx.objectStore(store).delete(id);
    tx.oncomplete=()=>res();
    tx.onerror=()=>rej();
  });
}
function dbClear(store){
  return new Promise((res,rej)=>{
    if(!db){lsSet('actions_'+store,[]);res();return;}
    const tx=db.transaction(store,'readwrite');
    tx.objectStore(store).clear();
    tx.oncomplete=()=>res();
  });
}
function lsGet(k,d){try{return JSON.parse(localStorage.getItem(k)||'null')??d;}catch{return d;}}
function lsSet(k,v){
  try{
    localStorage.setItem(k,JSON.stringify(v));
    return true;
  }catch(e){
    console.error('[lsSet FALHOU]',k,e.name,e.message);
    // Cota estourada? Tente liberar espaço removendo dados volumosos não-essenciais
    if(e.name==='QuotaExceededError'||/quota/i.test(e.message||'')){
      const cleanupKeys=['s1Rows_raw','s2Rows_raw','s3Rows_raw','s4Rows_raw','s4_raw','s3_raw','s2_raw','s1_raw'];
      let freed=false;
      for(const ck of cleanupKeys){
        if(localStorage.getItem(ck)){localStorage.removeItem(ck);freed=true;}
      }
      if(freed){
        try{ localStorage.setItem(k,JSON.stringify(v)); return true; }catch(e2){}
      }
      try{
        alert('⚠ Falha ao salvar "'+k+'": cota de armazenamento estourada.\n\n'+
              'O navegador limita ~5 MB por site. Tente:\n'+
              '• Limpar o histórico de semanas (Relatórios > Ver Histórico)\n'+
              '• Ou abrir o DevTools > Application > Local Storage e remover itens grandes');
      }catch(_){}
    }
    return false;
  }
}

// ── CADASTROS storage: IndexedDB primary, localStorage fallback ──
function dbCadGet(type){
  return new Promise(res=>{
    if(!db || ![...db.objectStoreNames].includes('cadastros')){res(null);return;}
    try{
      const tx=db.transaction('cadastros','readonly');
      const req=tx.objectStore('cadastros').get(type);
      req.onsuccess=()=>res(req.result?req.result.data:null);
      req.onerror=()=>res(null);
    }catch(e){res(null);}
  });
}
function dbCadPut(type, data){
  return new Promise(res=>{
    if(!db || ![...db.objectStoreNames].includes('cadastros')){res(false);return;}
    try{
      const tx=db.transaction('cadastros','readwrite');
      tx.objectStore('cadastros').put({type, data, updated_at:new Date().toISOString()});
      tx.oncomplete=()=>res(true);
      tx.onerror=()=>res(false);
    }catch(e){res(false);}
  });
}
async function dbCadCount(){
  if(!db || ![...db.objectStoreNames].includes('cadastros')) return null;
  return new Promise(res=>{
    const out = {};
    const tx=db.transaction('cadastros','readonly');
    const req=tx.objectStore('cadastros').getAll();
    req.onsuccess=()=>{
      for(const r of req.result||[]) out[r.type]=Object.keys(r.data||{}).length;
      res(out);
    };
    req.onerror=()=>res({});
  });
}
async function updateDbStatusDetailed(){
  const counts = await dbCadCount();
  if(counts){
    const total = (counts.motoristas||0)+(counts.auxiliares||0)+(counts.veiculos||0)+(counts.cidades||0);
    if(total>0){
      setDbStatus(true, `IndexedDB · ${total} cadastros`);
    } else {
      setDbStatus(true, 'IndexedDB conectado');
    }
  } else {
    setDbStatus(true, 'IndexedDB conectado');
  }
}

