function formatPhone(tel){
  if(!tel) return null;
  const raw = String(tel).trim();
  // Remove all non-digit characters
  let digits = raw.replace(/[^0-9]/g,'');
  if(!digits) return null;
  // Already has country code 55 prefix (13-14 digits)
  if(digits.length>=13 && digits.startsWith('55')) return digits;
  // Has country code 55 (12-13 digits starting with 55)
  if(digits.startsWith('55') && digits.length>=12) return digits;
  // 11 digits (DDD + 9-digit mobile): 15997123456
  if(digits.length===11) return '55'+digits;
  // 10 digits (DDD + 8-digit): 1597123456
  if(digits.length===10) return '55'+digits;
  // 9 digits (no DDD, 9-digit mobile like 997123456)
  // Try to infer DDD from context — use 15 (Sorocaba area) as default for Marquespan
  if(digits.length===9 && digits.startsWith('9')) return '5515'+digits;
  // 8 digits (no DDD, 8-digit mobile)
  if(digits.length===8) return '5515'+digits;
  // Give up
  return null;
}

