function goPage(id){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));
  const pg=document.getElementById('pg-'+id);
  if(pg){pg.classList.add('active');pg.classList.add('fade-up');setTimeout(()=>pg.classList.remove('fade-up'),400);}
  document.querySelectorAll('.nav-item').forEach(n=>{
    const oc=n.getAttribute('onclick')||'';
    if(oc.includes("'"+id+"'"))n.classList.add('active');
  });
  // 📱 Sincroniza a barra inferior mobile
  syncMobileNav(id);
  document.getElementById('top-title').textContent=PAGES[id]||id;
  if(id==='historico'){renderHistorico();renderPhonesTable();}
  if(id==='relatorios'){updateRelStats();}
  if(id==='step3'){
    // Auto-carrega semanas e vínculos na primeira visita ao passo 3
    const sel = document.getElementById('sel-semana-escala');
    if(sel && (sel.options.length <= 1 || sel.options[0].value === '')) {
      inicializarSemanasEscala();
    }
    // Carrega vínculos persistidos para a filial do usuário
    const filialVinc = (document.getElementById('sel-filial-escala')?.value || '').trim()
                    || (JSON.parse(localStorage.getItem('usuarioLogado') || '{}').filial || '').trim();
    if(filialVinc) carregarVinculos(filialVinc);
  }
  if(id==='cadastros'){
    cadCurrentType='motoristas';
    cadLoadAll();
    // ☁ Pull fresco da nuvem para garantir que a aba sempre reflita o que
    // qualquer outro usuário cadastrou (motoristas/auxiliares/veículos/cidades).
    if(typeof cadPullAllFromCloud === 'function') cadPullAllFromCloud().catch(e => console.warn('[cadPullAllFromCloud]', e));
  }
  if(id==='dashboard')refreshDashboard();
}

