// ═══════════════════════════════════════════════════════
//  UTILS
// ═══════════════════════════════════════════════════════
const esc=s=>s?String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])):'';
const norm=v=>v?String(v).trim().toUpperCase():'';

// ── MATCHING ENGINE ─────────────────────────────────────────
// Finds the full nome (from ponto) given an abbreviated nome (from escala)
// Uses cadastro data as the bridge
function resolveNome(nomeEscala){
  // Returns {nome_ponto, funcao, telefone, placa?, rota?} or null
  const key = norm(nomeEscala);
  if(!key) return null;

  // 🔒 Helper: ignora funcionários inativos (desligados) — não puxa para escalas novas
  const isActive = rec => !rec || rec.ativo!==false; // default true se não tem flag

  // Search in motoristas (apenas ATIVOS)
  for(const rec of Object.values(cadData.motoristas||{})){
    if(!isActive(rec)) continue;
    if(norm(rec.nome_escala)===key || norm(rec.nome_ponto)===key)
      return {...rec, tipo_func:'MOTORISTA'};
  }
  // Search in auxiliares (apenas ATIVOS)
  for(const rec of Object.values(cadData.auxiliares||{})){
    if(!isActive(rec)) continue;
    if(norm(rec.nome_escala)===key || norm(rec.nome_ponto)===key)
      return {...rec, tipo_func:'AUXILIAR'};
  }

  // Fuzzy: try partial word matching (também apenas ativos)
  const words = key.split(/\s+/).filter(w=>w.length>2);
  let bestMatch = null; let bestScore = 0;
  for(const store of ['motoristas','auxiliares']){
    for(const rec of Object.values(cadData[store]||{})){
      if(!isActive(rec)) continue;
      const escNorm = norm(rec.nome_escala||'');
      const pontoNorm = norm(rec.nome_ponto||'');
      // Count how many words from escala appear in the candidate
      for(const candidate of [escNorm, pontoNorm]){
        if(!candidate) continue;
        const matchCount = words.filter(w=>candidate.includes(w)).length;
        const score = matchCount / Math.max(words.length, 1);
        if(score > 0.7 && score > bestScore){
          bestScore = score;
          bestMatch = {...rec, tipo_func: store==='motoristas'?'MOTORISTA':'AUXILIAR'};
        }
      }
    }
  }
  if(bestMatch) return bestMatch;

  // Last resort: try to find full name in s1Rows by word matching
  // This allows WhatsApp to work even without cadData entries
  if(typeof s1Rows!=='undefined'&&s1Rows.length){
    const words=key.split(/\s+/).filter(w=>w.length>2);
    for(const r of s1Rows){
      const rNorm=norm(r.nome);
      const matchCount=words.filter(w=>rNorm.includes(w)).length;
      if(matchCount>0&&matchCount/words.length>=0.8){
        // Found partial match in ponto data
        return {nome_escala:nomeEscala, nome_ponto:r.nome, telefone:null, tipo_func:null, _fromPonto:true};
      }
    }
  }
  return null;
}

// Get telefone for WhatsApp from cadastro (motoristas or auxiliares)
function getTelFromCad(nomeInput){
  if(!nomeInput) return null;
  const key = norm(nomeInput);
  for(const store of ['motoristas','auxiliares']){
    for(const rec of Object.values(cadData[store]||{})){
      const ep=norm(rec.nome_ponto||'');
      const ee=norm(rec.nome_escala||'');
      // Exact match first
      if(ep===key||ee===key) return rec.telefone||null;
      // Partial: one contains the other (handles abbrev vs full)
      if(ep&&key&&(ep.startsWith(key)||key.startsWith(ep))) return rec.telefone||null;
      if(ee&&key&&(ee.startsWith(key)||key.startsWith(ee))) return rec.telefone||null;
    }
  }
  return null;
}

// Get funcao (MOTORISTA/AUXILIAR) from cadastro by nome
function getFuncaoFromCad(nome){
  const key = norm(nome);
  for(const rec of Object.values(cadData.motoristas||{})){
    if(norm(rec.nome_ponto)===key || norm(rec.nome_escala)===key) return 'MOTORISTA';
  }
  for(const rec of Object.values(cadData.auxiliares||{})){
    if(norm(rec.nome_ponto)===key || norm(rec.nome_escala)===key) return 'AUXILIAR';
  }
  return null;
}
const uid=()=>crypto.randomUUID?crypto.randomUUID():'id_'+Math.random().toString(36).slice(2,11);
const isSpec=v=>!v||SPECIALS.has(norm(v))||norm(v).includes('NAN')||String(v).trim()==='';

// Motivos LEGÍTIMOS de ausência (não geram infração nem mensagem WA)
const ABSENCE_REASONS = new Set(['FOLGA','FERIAS','FÉRIAS','FERIADO','FERIADO NACIONAL','FALTA','FALTOU','INSS','AFASTADO','AFASTAMENTO','AFAST.','ATESTADO','ATEST.','ATESTADO MEDICO','ATESTADO MÉDICO','ABONADO','ABONO','CARCERE','CÁRCERE','LICENCA','LICENÇA','LICENCA MEDICA','LICENÇA MÉDICA','MATERNIDADE','PATERNIDADE','SUSPENSO','SUSPENSAO','SUSPENSÃO']);
// Retorna o motivo de ausência normalizado se v for um motivo legítimo; senão null.
// (Empty/NaN/"SEM REGISTRO" = sem motivo → trata como infração de fato.)
function getAbsenceReason(v){
  if(!v) return null;
  const n = norm(v);
  if(!n || n==='NAN' || n==='SEM REGISTRO') return null;
  if(ABSENCE_REASONS.has(n)) return n;
  // Variações grafadas com acento
  if(/^(FERIAS|FÉRIAS|FERIADO|FALTA|FALTOU|FOLGA|INSS|AFASTADO|AFASTAMENTO|AFAST\.|ATESTADO|ATEST\.|ABONADO|ABONO|CARCERE|CÁRCERE|LICEN[CÇ]A|MATERNIDADE|PATERNIDADE|SUSPENS[AOÃ])/.test(n)) return n;
  return null;
}
function sleep(ms){return new Promise(r=>setTimeout(r,ms));}

function parseHHMM(v){
  const m=String(v).match(/^(\d{1,2}):(\d{2})$/);
  return m?{h:+m[1],m:+m[2]}:null;
}

function checkIssues(saida,entrada,interj){
  const iss=[];
  // Reconhece motivos legítimos de ausência (FOLGA/FERIAS/ATEST./INSS/ABONADO/...)
  const reasonS = (typeof getAbsenceReason==='function') ? getAbsenceReason(saida)  : null;
  const reasonE = (typeof getAbsenceReason==='function') ? getAbsenceReason(entrada) : null;

  // ── SAÍDA ──
  if(reasonS){
    iss.push({type:'AUSENCIA_JUSTIFICADA',text:reasonS});
  } else if(isSpec(saida)){
    iss.push({type:'SEM_SAIDA',text:'SEM REGISTRO'});
  } else {
    const t=parseHHMM(saida);
    if(t&&(t.h>19||(t.h===19&&t.m>20))) iss.push({type:'SAIDA_TARDIA',text:'SAÍDA APÓS 19:20'});
  }
  // ── ENTRADA ──
  if(reasonE){
    if(reasonE!==reasonS) iss.push({type:'AUSENCIA_JUSTIFICADA',text:reasonE});
  } else if(isSpec(entrada)){
    // Se a saída já tem justificativa legítima, entrada vazia faz sentido — não é "SEM REGISTRO"
    if(!reasonS) iss.push({type:'SEM_ENTRADA',text:'SEM REGISTRO'});
  } else {
    const t=parseHHMM(entrada);
    if(t&&(t.h<6||(t.h===6&&t.m<45))) iss.push({type:'ENTRADA_PRECOCE',text:'ENTRADA ANTES 06:45'});
  }
  // ── INTERJORNADA ── só calcula se ambas as pontas são horários reais
  if(!reasonS && !reasonE){
    if(!isSpec(interj)){
      const t=parseHHMM(interj);
      if(t&&(t.h*60+t.m)<660) iss.push({type:'IJ_CURTA',text:'INTERJORNADA < 11H'});
    } else if(interj!==undefined){
      iss.push({type:'SEM_INTERJ',text:'SEM REGISTRO'});
    }
  }
  return iss;
}

function obsCell(obs){
  if(!obs||obs==='OK')return'<span class="badge badge-ok">OK</span>';
  if(obs.includes('SEM REGISTRO'))return`<span class="badge badge-warn">${esc(obs.slice(0,40)+(obs.length>40?'…':''))}</span>`;
  return`<span class="badge badge-err">${esc(obs.slice(0,40)+(obs.length>40?'…':''))}</span>`;
}
function timeColor(v,type){
  if(getAbsenceReason(v))return't-ok';
  if(isSpec(v))return't-sem';
  const t=parseHHMM(v);if(!t)return't-sem';
  if(type==='s')return(t.h>19||(t.h===19&&t.m>20))?'t-err':'t-ok';
  if(type==='e')return(t.h<6||(t.h===6&&t.m<45))?'t-err':'t-ok';
  if(type==='r'){const m=t.h*60+t.m;return m<660?'t-err':'t-ok';}
  return'mono';
}
// Categorias STAT definidas pela regra de negócio Marquespan
// A escala pode vir com variações como V REST, V-REST, V - RESTR, V-RESTRI etc.
// O filtro normaliza essas variações, separa em CONJUNTO VIAGEM e CONJUNTO BATE E VOLTA.
const STAT_EMPTY_VALUE = '__VAZIO__';

const STAT_DESCR = {
  'V':'VIAGEM',
  'P':'PERNOITE',
  'R':'RETORNO',
  'V-REST':'VIAGEM RESTRIÇÃO',
  'V-RESTR':'VIAGEM RESTRIÇÃO',
  'V-RESTRI':'VIAGEM RESTRIÇÃO',
  'P-REST':'PERNOITE RESTRIÇÃO',
  'P-RESTR':'PERNOITE RESTRIÇÃO',
  'P-RESTRI':'PERNOITE RESTRIÇÃO',
  'R-REST':'RETORNO RESTRIÇÃO',
  'R-RESTR':'RETORNO RESTRIÇÃO',
  'R-RESTRI':'RETORNO RESTRIÇÃO',
  'REST.TAB':'RESTRIÇÃO TABOÃO DA SERRA',
  'ZMRC':'ZONA MÁXIMA DE RESTRIÇÃO',
  'ZMRC CPN':'ZONA MÁXIMA RESTRIÇÃO',
  'CAJU':'CAJU',
  'BUSCAR':'BUSCAR',
  'BGMNI':'BERGAMINI',
  'TRI+':'TRI MAIS',
  'ANDORIN':'ANDORINHA',
  'ANDORINHA':'ANDORINHA',
  'CNT SP':'CENTRO SÃO PAULO',
  'MRPOIRA':'MAIRIPORÃ',
  'MAIRIPORA':'MAIRIPORÃ'
};

const STAT_VIAGEM_ORDEM = [
  'V','P','R',
  'V-REST','V-RESTR','V-RESTRI',
  'P-REST','P-RESTR','P-RESTRI',
  'R-REST','R-RESTR','R-RESTRI'
];

const STAT_BV_ORDEM = [
  STAT_EMPTY_VALUE,
  'REST.TAB','ZMRC','ZMRC CPN','CAJU','BUSCAR','BGMNI','TRI+',
  'ANDORIN','ANDORINHA','CNT SP','MRPOIRA','MAIRIPORA'
];

function canonicalStat(s){
  let sv=String(s||'').trim().toUpperCase();
  sv=sv.normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  sv=sv.replace(/[–—]/g,'-').replace(/_/g,' ').replace(/\s+/g,' ').trim();
  sv=sv.replace(/\s*-\s*/g,'-');
  if(!sv||sv==='0'||sv==='FALSE'||sv==='NULL'||sv==='N/A'||sv==='-') return '';

  // Conjunto Viagem com variações de restrição
  if(sv==='VREST' || sv==='V REST') return 'V-REST';
  if(sv==='VRESTR' || sv==='V RESTR') return 'V-RESTR';
  if(sv==='VRESTRI' || sv==='V RESTRI') return 'V-RESTRI';
  if(sv==='PREST' || sv==='P REST') return 'P-REST';
  if(sv==='PRESTR' || sv==='P RESTR') return 'P-RESTR';
  if(sv==='PRESTRI' || sv==='P RESTRI') return 'P-RESTRI';
  if(sv==='RREST' || sv==='R REST') return 'R-REST';
  if(sv==='RRESTR' || sv==='R RESTR') return 'R-RESTR';
  if(sv==='RRESTRI' || sv==='R RESTRI') return 'R-RESTRI';

  // Bate e volta / restrições operacionais
  if(sv==='REST TAB' || sv==='REST-TAB' || sv==='RESTR TAB' || sv==='RESTR-TAB') return 'REST.TAB';
  if(sv==='ZMRC-CPN' || sv==='ZMRC/CPN' || sv==='ZMRC C.P.N') return 'ZMRC CPN';
  if(sv==='TRI MAIS' || sv==='TRI-MAIS' || sv==='TRI +') return 'TRI+';
  if(sv==='CNT-SP' || sv==='CENTRO SP' || sv==='CENTRO SAO PAULO') return 'CNT SP';
  if(sv==='MRPOIRÃ' || sv==='MRPOIRA' || sv==='MRAIPORA' || sv==='MAIRIPORA') return 'MRPOIRA';

  return sv;
}

// VIAGEM: V, P, R + variações com restrição
const STAT_VIAGEM = new Set(STAT_VIAGEM_ORDEM);

// BATE E VOLTA: vazios + restrições/localidades operacionais
const STAT_BV_NOMES = new Set(STAT_BV_ORDEM.filter(v=>v!==STAT_EMPTY_VALUE));

function getStatCategory(s){
  const sv=canonicalStat(s);
  if(!sv)return'bv'; // vazio = bate e volta
  if(STAT_VIAGEM.has(sv))return'viagem';
  if(STAT_BV_NOMES.has(sv))return'bv';
  // V/P/R com complemento ainda não cadastrado continuam como viagem
  if(/^[VPR][\s\-]/.test(sv)) return 'viagem';
  return'bv';
}

function statDescription(s){
  const sv=canonicalStat(s);
  if(!sv)return'SEM STAT / BATE E VOLTA';
  return STAT_DESCR[sv] || (getStatCategory(sv)==='viagem' ? 'VIAGEM' : 'BATE E VOLTA');
}

function statBadge(s){
  const sv=canonicalStat(s);
  if(!sv)return'<span class="t-gray">—</span>';
  const cat=getStatCategory(sv);
  const title=statDescription(sv);
  if(cat==='viagem')return`<span class="badge badge-warn" title="${esc(title)}">${esc(sv)}</span>`;
  return`<span class="badge badge-gray" title="${esc(title)}">${esc(sv)}</span>`;
}

// ── TERM HELPERS ──
function tlog(termId,type,msg){
  const t=document.getElementById(termId);
  if(!t)return;
  const cls=type==='ok'?'t-ok2':type==='warn'?'t-warn2':type==='err'?'t-err2':type==='dim'?'t-dim':'t-info';
  msg.split('\n').forEach(line=>{
    const s=document.createElement('span');s.className=cls;s.textContent=line;
    t.appendChild(s);t.appendChild(document.createElement('br'));
  });
  t.scrollTop=t.scrollHeight;
}
function setProg(pfId,plId,ppId,pct,label){
  const pf=document.getElementById(pfId),pl=document.getElementById(plId),pp=document.getElementById(ppId);
  if(pf){pf.style.width=pct+'%';if(pct>=100)pf.classList.add('done');}
  if(pl)pl.textContent=label;
  if(pp)pp.textContent=pct+'%';
}
function setUZ(id,title,hint,loaded){
  const z=document.getElementById(id);
  if(!z)return;
  if(loaded)z.classList.add('loaded');else z.classList.remove('loaded');
  const tEl=z.querySelector('.upload-title');
  const hEl=z.querySelector('.upload-hint');
  if(tEl)tEl.textContent=title;
  if(hEl)hEl.textContent=hint;
}

// ═══════════════════════════════════════════════════════
//  PASSO 1 — PROCESSAR PONTO DIÁRIO
// ═══════════════════════════════════════════════════════
async function handlePontoFile(file){
  if(!file)return;
  document.getElementById('s1-proc-card').style.display='';
  document.getElementById('s1-table-section').style.display='none';
  s1Rows=[];s1XLSXBin=null;
  tlog('s1-term','info',`$ Lendo: ${file.name} (${(file.size/1024).toFixed(0)} KB)`);
  const buf=await file.arrayBuffer();
  const wb=XLSX.read(buf,{type:'array',raw:false});
  tlog('s1-term','ok',`✓ Arquivo lido`);
  await sleep(60);
  setProg('s1-pf','s1-pl','s1-pp',10,'Detectando cabeçalho...');
  await sleep(60);

  const ws=wb.Sheets[wb.SheetNames[0]];
  const raw=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});

  let hdrRow=-1;
  for(let i=0;i<Math.min(raw.length,15);i++){
    const u=raw[i].map(v=>norm(v));
    if(u.includes('DATA')&&u.includes('NOME')){hdrRow=i;break;}
  }
  if(hdrRow<0){tlog('s1-term','err','✗ Cabeçalho não encontrado');return;}
  tlog('s1-term','ok',`✓ Cabeçalho na linha ${hdrRow+1}`);

  const hdrs=raw[hdrRow].map(v=>norm(v));
  const ci=name=>hdrs.indexOf(name);
  const iDATA=ci('DATA'),iNOME=ci('NOME');
  // Try both accented/unaccented variants for SAÍDA/ENTRADA
  const iSAI2=[ci('SAÍDA 2'),ci('SAIDA 2'),hdrs.findIndex(h=>h.includes('SAÍDA 2')||h.includes('SAIDA 2')||h.includes('SAIDA2'))].find(i=>i>=0)??-1;
  const iENT1=[ci('ENTRADA 1'),ci('ENTRADA1'),hdrs.findIndex(h=>h.includes('ENTRADA 1')||h.includes('ENTRADA1'))].find(i=>i>=0)??-1;
  tlog('s1-term','info',`  Mapa de colunas: DATA=${iDATA} NOME=${iNOME} SAÍDA2=${iSAI2} ENTRADA1=${iENT1}`);
  if(iSAI2<0||iENT1<0){tlog('s1-term','warn',`  ⚠ Colunas detectadas: ${hdrs.join(' | ')}`);}

  const byNome={};
  let total=0;
  for(let i=hdrRow+1;i<raw.length;i++){
    const r=raw[i];
    let nome=norm(r[iNOME]||'');
    const dataRaw=String(r[iDATA]||'').trim();
    if(!nome||!dataRaw||dataRaw.toUpperCase()==='TOTAL')continue;
    if(nome.startsWith('LOG NOT'))continue;
    nome=nome.replace(/^LOG\s*T?\s*-\s*/i,'').replace(/\s+/g,' ').trim();
    const dateParsed=parseDateStr(dataRaw);if(!dateParsed)continue;
    if(!byNome[nome])byNome[nome]=[];
    byNome[nome].push({nome,data:dateParsed,saida2:String(r[iSAI2]||'').trim(),entrada1:String(r[iENT1]||'').trim()});
    total++;
  }
  setProg('s1-pf','s1-pl','s1-pp',30,`${Object.keys(byNome).length} funcionários identificados...`);
  await sleep(60);
  tlog('s1-term','info',`→ ${Object.keys(byNome).length} funcionários, ${total} linhas`);

  s1Rows=[];
  const names=Object.keys(byNome).sort();
  for(let ni=0;ni<names.length;ni++){
    const nome=names[ni];
    const group=byNome[nome].sort((a,b)=>a.data-b.data);
    for(let i=1;i<group.length;i++){
      const prev=group[i-1],curr=group[i];
      const sT=parseHHMM(prev.saida2),eT=parseHHMM(curr.entrada1);
      let desc='';
      if(sT&&eT){
        let m=(eT.h*60+eT.m)-(sT.h*60+sT.m);
        if(m<=0)m+=24*60;
        desc=`${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`;
      }
      const saida=sT?`${String(sT.h).padStart(2,'0')}:${String(sT.m).padStart(2,'0')}`:prev.saida2;
      const entrada=eT?`${String(eT.h).padStart(2,'0')}:${String(eT.m).padStart(2,'0')}`:curr.entrada1;
      const flags=[];
      if(!isSpec(saida)){const t=parseHHMM(saida);if(t&&(t.h>19||(t.h===19&&t.m>20)))flags.push('ST');}
      if(!isSpec(entrada)){const t=parseHHMM(entrada);if(t&&(t.h<6||(t.h===6&&t.m<45)))flags.push('EA');}
      if(desc){const t=parseHHMM(desc);if(t&&(t.h*60+t.m)<660)flags.push('IJ');}
      s1Rows.push({nome,dataStr:fmtDate(prev.data),dataObj:prev.data,dataAba:fmtAba(prev.data),saida,entrada,descanso:desc,flags});
    }
    if(ni%60===0){setProg('s1-pf','s1-pl','s1-pp',30+Math.floor((ni/names.length)*50),`Calculando... ${ni}/${names.length}`);await sleep(0);}
  }

  setProg('s1-pf','s1-pl','s1-pp',85,'Gerando XLSX formatado...');
  await sleep(80);
  s1XLSXBin=buildS1XLSX(s1Rows);

  const stC=s1Rows.filter(r=>r.flags.includes('ST')).length;
  const eaC=s1Rows.filter(r=>r.flags.includes('EA')).length;
  const ijC=s1Rows.filter(r=>r.flags.includes('IJ')).length;
  tlog('s1-term','ok',`✓ ${s1Rows.length} pares calculados`);
  tlog('s1-term','warn',`→ ST:${stC} EA:${eaC} IJ:${ijC}`);

  setProg('s1-pf','s1-pl','s1-pp',100,'Concluído!');
  const abasGeradas=[...new Set(s1Rows.map(r=>r.dataAba))];
  setUZ('dz-ponto',file.name,`${s1Rows.length} registros · ${abasGeradas.length} aba(s): ${abasGeradas.slice(0,5).join(', ')}${abasGeradas.length>5?'...':''}`,true);

  const nomes=[...new Set(s1Rows.map(r=>r.nome))].length;
  const reconhecidos=[...new Set(s1Rows.map(r=>r.nome))].filter(n=>getFuncaoFromCad(n)).length;
  document.getElementById('step1-result').innerHTML=`
    <div class="stats-grid" style="grid-template-columns:repeat(2,1fr);gap:8px;margin-bottom:0">
      <div class="stat-card blue" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${nomes}</div>
        <div class="stat-label">Funcionários</div>
      </div>
      <div class="stat-card ${reconhecidos===nomes?'green':'orange'}" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${reconhecidos}/${nomes}</div>
        <div class="stat-label">No Cadastro</div>
      </div>
      <div class="stat-card purple" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${s1Rows.length}</div>
        <div class="stat-label">Pares de jornada</div>
      </div>
      <div class="stat-card red" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${stC+eaC+ijC}</div>
        <div class="stat-label">Total infrações</div>
      </div>
      <div class="stat-card orange" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${ijC}</div>
        <div class="stat-label">Interj. &lt; 11h</div>
      </div>
      <div class="stat-card red" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${stC}</div>
        <div class="stat-label">Saídas após 19:20</div>
      </div>
      <div class="stat-card blue" style="padding:10px">
        <div class="stat-val" style="font-size:18px">${eaC}</div>
        <div class="stat-label">Entradas ant. 06:45</div>
      </div>
    </div>`;

  document.getElementById('s1-table-section').style.display='';
  setStepDone(1);
  filterS1Table();
  await saveSession('step1',{arquivo:file.name,total:s1Rows.length,stC,eaC,ijC,ts:new Date().toISOString()});
  refreshDashboard();
}

function buildS1XLSX(rows){
  const wb=XLSX.utils.book_new();
  const byAba={};
  rows.forEach(r=>{if(!byAba[r.dataAba])byAba[r.dataAba]=[];byAba[r.dataAba].push(r);});
  // Sort abas chronologically
  const sortedAbas=Object.keys(byAba).sort((a,b)=>{
    const pa=a.split('.'),pb=b.split('.');
    return new Date(2000+parseInt(pa[2]),parseInt(pa[1])-1,parseInt(pa[0]))-
           new Date(2000+parseInt(pb[2]),parseInt(pb[1])-1,parseInt(pb[0]));
  });
  for(const aba of sortedAbas){
    const abaRows=byAba[aba];
    // Row 0: column headers (N° FOLHA, NOME, SAÍDA, ENTRADA, DESCANSO)
    // Row 1: date row (blank, blank, dateStr saída, dateStr entrada, blank)
    // Row 2+: data
    const dateStr=abaRows[0].dataStr;
    // Calculate next day date string
    const parts=aba.split('.');
    const dtObj=new Date(2000+parseInt(parts[2]),parseInt(parts[1])-1,parseInt(parts[0]));
    dtObj.setDate(dtObj.getDate()+1);
    const nextDateStr=`${String(dtObj.getDate()).padStart(2,'0')}/${String(dtObj.getMonth()+1).padStart(2,'0')}/${dtObj.getFullYear()}`;
    const data=[
      ['N° FOLHA','NOME','SAÍDA','ENTRADA','DESCANSO'],
      ['','',dateStr,nextDateStr,''],
      ...abaRows.map(r=>['',r.nome,r.saida,r.entrada,r.descanso||''])
    ];
    const ws=XLSX.utils.aoa_to_sheet(data);
    ws['!cols']=[{wch:10},{wch:40},{wch:12},{wch:12},{wch:12}];
    // Freeze first 2 rows
    ws['!freeze']={xSplit:0,ySplit:2,topLeftCell:'A3',activePane:'bottomLeft'};
    XLSX.utils.book_append_sheet(wb,ws,aba);
  }
  return XLSX.write(wb,{type:'array',bookType:'xlsx'});
}

function filterS1Table(){s1Search=document.getElementById('s1-search').value.toLowerCase();renderS1Table();}
function setS1Filter(f,el){s1Filter=f;document.querySelectorAll('#s1-chips .chip').forEach(c=>c.classList.remove('active'));el.classList.add('active');renderS1Table();}
function renderS1Table(){
  let rows=[...s1Rows];
  if(s1Search)rows=rows.filter(r=>r.nome.toLowerCase().includes(s1Search));
  if(s1Filter==='ST')rows=rows.filter(r=>r.flags.includes('ST'));
  else if(s1Filter==='EA')rows=rows.filter(r=>r.flags.includes('EA'));
  else if(s1Filter==='IJ')rows=rows.filter(r=>r.flags.includes('IJ'));
  else if(s1Filter==='ok')rows=rows.filter(r=>!r.flags.length);
  document.getElementById('s1-count').textContent=`${rows.length} de ${s1Rows.length} registros`;
  const tbody=document.getElementById('s1-tbody');
  tbody.innerHTML=rows.slice(0,500).map((r,i)=>{
    const fn=getFuncaoFromCad(r.nome);
    const fnBadge=fn
      ?`<span style="padding:1px 7px;border-radius:10px;font-size:10px;font-weight:700;background:${fn==='MOTORISTA'?'var(--blue-l)':'var(--purple-l)'};color:${fn==='MOTORISTA'?'var(--blue)':'var(--purple)'}">${fn==='MOTORISTA'?'MOT':'AUX'}</span>`
      :'<span class="t-gray" style="font-size:11px">—</span>';
    const status=r.flags.length
      ?r.flags.map(f=>f==='ST'?'<span class="badge badge-warn">Saída tard.</span>':f==='EA'?'<span class="badge badge-blue">Ent. antec.</span>':'<span class="badge badge-err">Interj.&lt;11h</span>').join(' ')
      :'<span class="badge badge-ok">OK</span>';
    return`<tr>
      <td class="mono t-gray">${i+1}</td>
      <td style="font-weight:500">${esc(r.nome)}</td>
      <td style="text-align:center">${fnBadge}</td>
      <td class="mono t-gray">${r.dataStr}</td>
      <td class="${timeColor(r.saida,'s')}">${esc(r.saida)||'—'}</td>
      <td class="${timeColor(r.entrada,'e')}">${isSpec(r.entrada)?`<span class="t-gray">${esc(r.entrada)}</span>`:esc(r.entrada)}</td>
      <td class="${timeColor(r.descanso,'r')}">${r.descanso||'—'}</td>
      <td>${status}</td>
    </tr>`;
  }).join('');
}

