function usarS1NoPasso2(){
  if(!s1XLSXBin) return alert('Gere o resultado do Passo 1 primeiro (carregue o ponto diário).');
  // Carrega o binário gerado direto na variável de trabalho do Passo 2
  wb_ij = XLSX.read(s1XLSXBin, {type:'array', cellFormula:true});
  const sheets = wb_ij.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
  setUZ('dz-ij', '✓ Recebido do Passo 1 (em memória)', `${sheets.length} aba(s): ${sheets.join(', ')}`, true);
  // Auto-gera CONTROLE dos cadastros se ainda não houver
  if(!wb_ctrl){
    wb_ctrl = buildCtrlFromCadastros();
    setUZ('dz-ctrl', '✓ Gerado automaticamente', 'dos cadastros embutidos · sem upload necessário', true);
  }
  goPage('step2');
  if(wb_ij && wb_ctrl) buildS2Mapping();
  setTimeout(()=>{
    const el = document.getElementById('s2-chain-info');
    if(el){ el.style.display=''; el.textContent='✓ Dados recebidos do Passo 1 automaticamente — não precisou exportar/importar.'; setTimeout(()=>el.style.display='none', 7000); }
  }, 400);
}
