function handleIJFile(file){
  file.arrayBuffer().then(buf=>{
    wb_ij=XLSX.read(buf,{type:'array',cellFormula:true});
    const sheets=wb_ij.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
    setUZ('dz-ij',file.name,`${sheets.length} aba(s): ${sheets.join(', ')}`,true);
    // Auto-gerar CONTROLE em memória a partir dos cadastros se não carregado
    if(!wb_ctrl){
      wb_ctrl = buildCtrlFromCadastros();
      setUZ('dz-ctrl','✓ Gerado automaticamente','dos cadastros embutidos · sem upload necessário',true);
    }
    if(wb_ij&&wb_ctrl)buildS2Mapping();
  });
}
function handleCtrlFile(file){
  file.arrayBuffer().then(buf=>{
    wb_ctrl=XLSX.read(buf,{type:'array',cellFormula:true});
    const sheets=wb_ctrl.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
    setUZ('dz-ctrl',file.name,`${sheets.length} abas de datas`,true);
    if(wb_ij&&wb_ctrl)buildS2Mapping();
  });
}

// ── Gera CONTROLE.xlsx em memória a partir dos cadastros embutidos ────
// Quando o usuário NÃO carrega o CONTROLE.xlsx, esta função monta um
// workbook completo com MOTORISTA / AUXILIAR / CIDADE prontos para o
// fluxo do Passo 2 e Passo 3. As abas de datas serão criadas em runStep2.
function buildCtrlFromCadastros(){
  const wb = XLSX.utils.book_new();

  // ── Aba MOTORISTA ────────────────────────────────
  const motRows = [
    ['N° IDENTIFICADOR','MOTORISTA','NOME COMPLETO','CPF','ADMISSÃO','TELEFONE CORPORATIVO','TELEFONE PESSOAL']
  ];
  Object.values(cadData.motoristas||{}).forEach((m,i)=>{
    motRows.push([
      i+1,
      m.nome_escala||'',
      m.nome_ponto||'',
      m.cpf||'',
      m.admissao||'',
      m.tel_corp||'',
      m.telefone||''
    ]);
  });
  const wsMot = XLSX.utils.aoa_to_sheet(motRows);
  wsMot['!cols'] = [{wch:18},{wch:28},{wch:38},{wch:14},{wch:12},{wch:20},{wch:18}];
  XLSX.utils.book_append_sheet(wb, wsMot, 'MOTORISTA');

  // ── Aba AUXILIAR ─────────────────────────────────
  const auxRows = [
    ['N° IDENTIFICADOR','NOME','NOME COMPLETO','CPF','ADMISSÃO','TELEFONE PESSOAL']
  ];
  Object.values(cadData.auxiliares||{}).forEach((a,i)=>{
    auxRows.push([
      i+1,
      a.nome_escala||'',
      a.nome_ponto||'',
      a.cpf||'',
      a.admissao||'',
      a.telefone||''
    ]);
  });
  const wsAux = XLSX.utils.aoa_to_sheet(auxRows);
  wsAux['!cols'] = [{wch:18},{wch:28},{wch:38},{wch:14},{wch:12},{wch:18}];
  XLSX.utils.book_append_sheet(wb, wsAux, 'AUXILIAR');

  // ── Aba CIDADE ───────────────────────────────────
  const cidRows = [['ROTA','CIDADE']];
  Object.values(cadData.cidades||{}).forEach(c=>{
    cidRows.push([
      isNaN(Number(c.rota))?c.rota:Number(c.rota),
      c.cidade||''
    ]);
  });
  const wsCid = XLSX.utils.aoa_to_sheet(cidRows);
  wsCid['!cols'] = [{wch:8},{wch:48}];
  XLSX.utils.book_append_sheet(wb, wsCid, 'CIDADE');

  console.log('[Passo 2] CONTROLE gerado em memória a partir dos cadastros:',
    motRows.length-1,'motoristas,',
    auxRows.length-1,'auxiliares,',
    cidRows.length-1,'cidades');
  return wb;
}
// ── Helpers for date sheet formatting ─────────────────
function makeDateSheetABA(sheetName, names) {
  // sheetName e.g. "17.04.26"
  // Builds a complete CONTROLE date sheet from scratch using the same
  // structure as the existing sheets: 3 header rows + data rows with formula.
  const parts = sheetName.split('.');
  const d = parseInt(parts[0]), mo = parseInt(parts[1]), y = 2000 + parseInt(parts[2]);
  const dt = new Date(y, mo - 1, d);
  const fmtD = v => `${String(v.getDate()).padStart(2,'0')}/${String(v.getMonth()+1).padStart(2,'0')}/${v.getFullYear()}`;
  const dateStr  = fmtD(dt);
  const nextDate = new Date(dt); nextDate.setDate(nextDate.getDate() + 1);
  const nextStr  = fmtD(nextDate);

  const ws = {};
  const BLACK = 'FF000000';
  const WHITE = 'FFFFFFFF';
  const hdrStyle = {
    font:      { name:'Calibri', sz:11, bold:true, color:{ rgb:WHITE } },
    fill:      { patternType:'solid', fgColor:{ rgb:BLACK } },
    alignment: { horizontal:'center', vertical:'center' },
    border:    { top:{style:'thin'},bottom:{style:'thin'},left:{style:'thin'},right:{style:'thin'} }
  };
  const dataStyle = n => ({
    font:      { name:'Calibri', sz:11 },
    alignment: { horizontal:'left', vertical:'center' }
  });
  const timeStyle = {
    font:      { name:'Calibri', sz:11 },
    alignment: { horizontal:'center', vertical:'center' },
    numFmt:    'h:mm'
  };

  // Row 1 — title bar: A=empty, B=dateStr, C=SAÍDA, D=ENTRADA, E=INTERJ
  const r1vals = [null, dateStr, 'SAÍDA', 'ENTRADA', 'INTERJ'];
  r1vals.forEach((v,ci) => {
    const addr = XLSX.utils.encode_cell({r:0,c:ci});
    ws[addr] = { v: v===null?'':v, t:'s', s: hdrStyle };
  });

  // Row 2 — date subheader: C=dateStr, D=nextStr
  [[1,'',hdrStyle],[2,dateStr,hdrStyle],[3,nextStr,hdrStyle]].forEach(([ci,v,s]) => {
    const addr = XLSX.utils.encode_cell({r:1,c:ci});
    ws[addr] = { v, t:'s', s };
  });
  // fill other row2 cols with black background
  [0,4].forEach(ci => {
    const addr = XLSX.utils.encode_cell({r:1,c:ci});
    ws[addr] = { v:'', t:'s', s: hdrStyle };
  });

  // Row 3 — column labels
  const labels = ['N° FOLHA','NOME','SAÍDA','ENTRADA','DESCANSO'];
  labels.forEach((lbl,ci) => {
    const addr = XLSX.utils.encode_cell({r:2,c:ci});
    ws[addr] = { v:lbl, t:'s', s: hdrStyle };
  });

  // Data rows (starting row index 3 = Excel row 4)
  const lastDataRow = names.length + 3; // 0-indexed last row
  names.forEach((nome, ni) => {
    const ri = ni + 3; // 0-indexed
    const rNum = ri + 1; // 1-indexed for formulas

    // Col A — N° FOLHA (empty)
    ws[XLSX.utils.encode_cell({r:ri,c:0})] = { v:'', t:'s' };
    // Col B — NOME
    ws[XLSX.utils.encode_cell({r:ri,c:1})] = { v:nome, t:'s' };
    // Col C — SAÍDA (empty, will be filled)
    ws[XLSX.utils.encode_cell({r:ri,c:2})] = { v:'', t:'s' };
    // Col D — ENTRADA (empty, will be filled)
    ws[XLSX.utils.encode_cell({r:ri,c:3})] = { v:'', t:'s' };
    // Col E — DESCANSO formula (identical to existing sheets)
    const f = `=IFERROR(IF(OR(C${rNum}="Atest.",C${rNum}="Ferias",C${rNum}="FOLGA",C${rNum}="Faltou",C${rNum}="FALTA",C${rNum}="INSS",C${rNum}="ABONADO",C${rNum}="",D${rNum}="",D${rNum}="FALTA",D${rNum}="INSS",D${rNum}="ABONADO",D${rNum}="Atest.",D${rNum}="Ferias",D${rNum}="FOLGA"),C${rNum},IF(D${rNum}>=C${rNum},D${rNum}-C${rNum},1*(1-C${rNum})+D${rNum})),"Erro")`;
    ws[XLSX.utils.encode_cell({r:ri,c:4})] = { f, t:'n', z:'h:mm' };
  });

  // Sheet range
  ws['!ref'] = XLSX.utils.encode_range({ s:{r:0,c:0}, e:{r:lastDataRow,c:4} });
  // Column widths matching existing sheets
  ws['!cols'] = [
    {wch:14},   // A — N° FOLHA
    {wch:51},   // B — NOME
    {wch:11},   // C — SAÍDA
    {wch:14},   // D — ENTRADA
    {wch:15}    // E — DESCANSO
  ];
  // Freeze at A4 (row 3 = 0-indexed index 3)
  ws['!freeze'] = { xSplit:0, ySplit:3, topLeftCell:'A4', activePane:'bottomLeft' };

  return ws;
}

// ─────────────────────────────────────────────────────
function buildS2Mapping(){
  const ijSheets=wb_ij.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
  const ctrlSet=new Set(wb_ctrl.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s)));
  const toCreate=ijSheets.filter(s=>!ctrlSet.has(s));
  const toUpdate=ijSheets.filter(s=>ctrlSet.has(s));
  const cont=document.getElementById('s2-map-rows');

  // Summary alert
  let alertHtml='';
  if(toCreate.length){
    alertHtml=`<div style="display:flex;align-items:center;gap:10px;padding:12px 16px;background:var(--blue-l);border:1px solid var(--blue-b);border-radius:var(--r);margin-bottom:10px;font-size:13px">
      <svg style="width:16px;height:16px;stroke:var(--blue);fill:none;stroke-width:2;flex-shrink:0" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
      <div><strong>${toCreate.length} aba(s)</strong> serão <strong>criadas automaticamente</strong> no Controle com cabeçalho, nomes e fórmulas. <strong>${toUpdate.length} aba(s)</strong> já existem e receberão os dados.</div>
    </div>`;
  }

  cont.innerHTML = alertHtml + ijSheets.map(s=>{
    const exists = ctrlSet.has(s);
    const bg   = exists ? 'var(--green-l)' : 'var(--blue-l)';
    const bord = exists ? 'var(--green-b)' : 'var(--blue-b)';
    const icon = exists ? '✓' : '＋';
    const iconColor = exists ? 'var(--green)' : 'var(--blue)';
    const label = exists ? 'Atualizar horários' : 'Criar aba automaticamente';
    return`<div style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:${bg};border:1px solid ${bord};border-radius:var(--r);margin-bottom:4px;font-size:12.5px">
      <span class="badge badge-blue mono">${esc(s)}</span>
      <span style="color:var(--text3)">→</span>
      <span style="color:${iconColor};font-weight:700;font-size:15px">${icon}</span>
      <span style="color:${iconColor};font-weight:600">${label}</span>
      <span style="margin-left:auto;font-size:11px;color:var(--text3)">${exists?'SAÍDA+ENTRADA por nome':'aba nova · nomes da interjornada · fórmula DESCANSO'}</span>
    </div>`;
  }).join('');
  document.getElementById('s2-map-section').style.display='';
}

async function runStep2(){
  document.getElementById('btn-s2-run').disabled=true;
  document.getElementById('s2-proc-card').style.display='';
  document.getElementById('s2-dl-section').style.display='none';

  const bin=XLSX.write(wb_ctrl,{type:'array',bookType:'xlsx',cellFormula:true});
  const wb_res=XLSX.read(bin,{type:'array',cellFormula:true});

  const ijSheets=wb_ij.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
  const ctrlSet=new Set(wb_res.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s)));
  let totalCopied=0, totalCreated=0;

  tlog('s2-term','info','$ Iniciando processamento...');
  await sleep(60);

  for(let mi=0;mi<ijSheets.length;mi++){
    const sheet=ijSheets[mi];
    setProg('s2-pf','s2-pl','s2-pp',Math.floor((mi/ijSheets.length)*90),`Processando ${sheet}...`);

    // ── Read IJ source data ──────────────────────────
    const srcRows=XLSX.utils.sheet_to_json(wb_ij.Sheets[sheet],{header:1,defval:'',raw:false});
    const ijMap={};
    // interjornada_formatada: row0=headers, row1=dates, row2+=data
    // Auto-detect data start: skip rows until we find non-header nome in col 1
    let ijDataStart=1;
    for(let i=1;i<Math.min(srcRows.length,5);i++){
      const v=norm(srcRows[i][1]);
      if(v&&!['NOME','N° FOLHA','NFOLHA','DATA'].includes(v)&&!/^\d{2}\/\d{2}\//.test(v)){ijDataStart=i;break;}
    }
    for(let i=ijDataStart;i<srcRows.length;i++){
      const nome=norm(srcRows[i][1]);
      if(!nome||nome==='NOME')continue;
      const saida=String(srcRows[i][2]||'').trim();
      const entrada=String(srcRows[i][3]||'').trim();
      if(nome)ijMap[nome]={saida,entrada};
    }
    const ijNames=Object.keys(ijMap); // preserves IJ order

    // ── Case A: aba already exists in CONTROLE ──────
    if(ctrlSet.has(sheet)){
      tlog('s2-term','info',`→ ${sheet} (existe · atualizando ${ijNames.length} nomes)`);
      const dstRows=XLSX.utils.sheet_to_json(wb_res.Sheets[sheet],{header:1,defval:'',raw:false});
      let copied=0;
      for(let ri=3;ri<dstRows.length;ri++){
        const nome=norm(dstRows[ri][1]);if(!nome)continue;
        const ij=ijMap[nome];if(!ij)continue;
        const cC=XLSX.utils.encode_cell({r:ri,c:2}),cD=XLSX.utils.encode_cell({r:ri,c:3});
        if(ij.saida) wb_res.Sheets[sheet][cC]={v:ij.saida,t:'s'};
        if(ij.entrada)wb_res.Sheets[sheet][cD]={v:ij.entrada,t:'s'};
        copied++;
      }
      tlog('s2-term','ok',`  ✓ ${copied} registros atualizados`);
      totalCopied+=copied;

    // ── Case B: aba NÃO existe — criar do zero ──────
    } else {
      tlog('s2-term','info',`→ ${sheet} (NOVA · criando aba com ${ijNames.length} funcionários)`);
      await sleep(20);

      // 1. Build the sheet structure with all names
      const ws = makeDateSheetABA(sheet, ijNames);

      // 2. Fill SAÍDA and ENTRADA for each name
      let filled=0;
      ijNames.forEach((nome,ni)=>{
        const ri=ni+3; // 0-indexed
        const ij=ijMap[nome];
        if(ij){
          if(ij.saida) ws[XLSX.utils.encode_cell({r:ri,c:2})]={v:ij.saida,t:'s'};
          if(ij.entrada)ws[XLSX.utils.encode_cell({r:ri,c:3})]={v:ij.entrada,t:'s'};
          filled++;
        }
      });

      // 3. Insert the sheet into the workbook in the right position
      // Find correct position: after other date sheets, before SEGUNDA etc.
      const existingDates = wb_res.SheetNames.filter(s=>/^\d{2}\.\d{2}\.\d{2}$/.test(s));
      const nonDateSheets = wb_res.SheetNames.filter(s=>!/^\d{2}\.\d{2}\.\d{2}$/.test(s));
      const allDates = [...existingDates, sheet].sort((a,b)=>{
        const pa=a.split('.'),pb=b.split('.');
        const da=new Date(2000+parseInt(pa[2]),parseInt(pa[1])-1,parseInt(pa[0]));
        const db=new Date(2000+parseInt(pb[2]),parseInt(pb[1])-1,parseInt(pb[0]));
        return da-db;
      });
      // Rebuild SheetNames order
      const firstNonDate = wb_res.SheetNames.find(s=>!/^\d{2}\.\d{2}\.\d{2}$/.test(s));
      const insertBefore = firstNonDate ? wb_res.SheetNames.indexOf(firstNonDate) : wb_res.SheetNames.length;
      const sheetIdx = allDates.indexOf(sheet);
      const insertAt = insertBefore - existingDates.length + sheetIdx;

      wb_res.SheetNames.splice(Math.max(0,insertAt), 0, sheet);
      wb_res.Sheets[sheet] = ws;

      tlog('s2-term','ok',`  ✓ Aba criada · ${filled} registros inseridos`);
      totalCreated++;
      totalCopied+=filled;
    }
    await sleep(30);
  }

  setProg('s2-pf','s2-pl','s2-pp',100,'Concluído!');
  tlog('s2-term','ok',`\n✓ ${totalCopied} registros escritos · ${totalCreated} aba(s) criada(s)`);
  s2Bin=XLSX.write(wb_res,{type:'array',bookType:'xlsx',cellFormula:true});

  const ts=new Date().toISOString().slice(0,10).replace(/-/g,'_');
  document.getElementById('s2-dl-name').textContent=`CONTROLE_DE_JORNADA_${ts}.xlsx`;
  document.getElementById('s2-dl-desc').textContent=
    `${totalCopied} registros · ${totalCreated} aba(s) criada(s) · fórmulas DESCANSO preservadas`;
  document.getElementById('s2-dl-section').style.display='';
  document.getElementById('btn-s2-run').disabled=false;
  setStepDone(2);
  await saveSession('step2',{totalCopied,totalCreated,ts:new Date().toISOString()});
  refreshDashboard();
}
function downloadS2XLSX(){if(!s2Bin)return;dl(s2Bin,`CONTROLE_DE_JORNADA_${new Date().toISOString().slice(0,10)}.xlsx`);}

