function buildMap(wb,sheet,colShort,colFull){
  const map={};

  // ── Fonte 1: XLSX (CONTROLE_DE_JORNADA.xlsx abas MOTORISTA/AUXILIAR) ──
  const ws=wb?wb.Sheets[sheet]:null;
  if(ws){
    const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});
    if(rows.length){
      let hdrIdx=0;
      for(let i=0;i<Math.min(rows.length,8);i++){
        const u=rows[i].map(v=>norm(v));
        if(u.some(v=>v==='NOME COMPLETO')){hdrIdx=i;break;}
      }
      const hdrs=rows[hdrIdx].map(v=>norm(v));
      const shortCol=hdrs.indexOf('MOTORISTA')>=0?hdrs.indexOf('MOTORISTA'):hdrs.indexOf('NOME');
      const fullCol=hdrs.indexOf('NOME COMPLETO');
      const useShort=shortCol>=0?shortCol:colShort;
      const useFull=fullCol>=0?fullCol:colFull;
      for(let i=hdrIdx+1;i<rows.length;i++){
        const s=norm(rows[i][useShort]),f=norm(rows[i][useFull]);
        if(s&&s!=='MOTORISTA'&&s!=='NOME')map[s]=f||s;
      }
    }
  }

  // ── Fonte 2: cadData (cadastro do sistema) — sobrepõe o XLSX ──
  // Motoristas: nome_escala → nome_ponto
  const cadStore = sheet.toLowerCase().includes('motor') ? 'motoristas' : 'auxiliares';
  for(const rec of Object.values(cadData[cadStore]||{})){
    const escNorm = norm(rec.nome_escala||'');
    const pontoNorm = norm(rec.nome_ponto||'');
    if(escNorm && pontoNorm){
      map[escNorm] = pontoNorm; // nome_escala → nome_ponto
    }
  }

  return map;
}

// Builds mapa from cadData alone (no xlsx needed) — used when CONTROLE not loaded
function buildMapFromCad(tipo){
  const map={};
  const store = tipo==='MOTORISTA'?'motoristas':'auxiliares';
  for(const rec of Object.values(cadData[store]||{})){
    const escNorm=norm(rec.nome_escala||'');
    const pontoNorm=norm(rec.nome_ponto||'');
    if(escNorm&&pontoNorm) map[escNorm]=pontoNorm;
    // Also map nome_ponto → nome_ponto (self, for direct lookup)
    if(pontoNorm) map[pontoNorm]=pontoNorm;
  }
  return map;
}

