// Carrega semanas disponíveis na tabela escala e preenche o select
async function inicializarSemanasEscala(){
  const selSemana = document.getElementById('sel-semana-escala');
  const selFilial = document.getElementById('sel-filial-escala');
  if(!selSemana) return;

  // ── 1. Carrega filiais (igual escala.js) ──────────────────
  if(selFilial){
    try {
      const resp = await sbFetch('/rest/v1/filiais?select=nome,sigla&order=nome.asc');
      if(resp.ok){
        const filiais = await resp.json();
        const usuFilial = JSON.parse(localStorage.getItem('usuarioLogado') || '{}').filial || '';
        selFilial.innerHTML = '<option value="">Selecione a filial...</option>' +
          (filiais || []).map(f => {
            const val = f.sigla || f.nome || '';
            const lbl = f.sigla ? `${f.nome} (${f.sigla})` : f.nome;
            return `<option value="${val}" ${val === usuFilial ? 'selected' : ''}>${lbl}</option>`;
          }).join('');
        // Se não selecionou nenhuma, tenta usar a do usuário logado diretamente
        if(!selFilial.value && usuFilial) selFilial.value = usuFilial;
      }
    } catch(e){ console.warn('[inicializarSemanasEscala] filiais', e); }
  }

  // ── 2. Gera semanas programaticamente (igual escala.js) ──
  // Base: 28/12/2025 = semana 1 de 2026
  const baseDate   = new Date(Date.UTC(2025, 11, 28));
  const hoje       = new Date();
  const diffDays   = Math.floor((hoje - baseDate) / (1000 * 60 * 60 * 24));
  let semanaAtual  = Math.floor(diffDays / 7) + 1;
  if(semanaAtual < 1)  semanaAtual = 1;
  if(semanaAtual > 53) semanaAtual = 53;

  // Lista de SEMANA 01 - 2026 até SEMANA 53 - 2026
  const semanas = [];
  for(let i = 1; i <= 53; i++){
    semanas.push(`SEMANA ${String(i).padStart(2,'0')} - 2026`);
  }

  selSemana.innerHTML = semanas.map(s => `<option value="${s}">${s}</option>`).join('');
  selSemana.value = `SEMANA ${String(semanaAtual).padStart(2,'0')} - 2026`;

  const btnUsar = document.getElementById('btn-usar-semana');
  if(btnUsar){ btnUsar.disabled = false; btnUsar.style.opacity = '1'; }
}

// ── Carrega escala pelas datas exatas do CONTROLE ──────────────────
// Usa a função RPC get_escala_por_datas — bypassa semana_nome
async function carregarEscalaPorDatasControle(){
  const filial = (document.getElementById('sel-filial-escala')?.value || '').trim()
              || (JSON.parse(localStorage.getItem('usuarioLogado') || '{}').filial || '').trim();
  if(!filial){ alert('Selecione a filial antes de carregar a escala.'); return; }
  if(!wb_ctrl2){ alert('Carregue o CONTROLE (lado esquerdo) primeiro.'); return; }

  // Extrai datas únicas das abas do CONTROLE (formato DD.MM.YY → YYYY-MM-DD)
  const dateSheets = (wb_ctrl2.SheetNames || []).filter(s => /^\d{2}\.\d{2}\.\d{2}$/.test(s));
  if(!dateSheets.length){ alert('O CONTROLE não tem abas de datas (DD.MM.YY).'); return; }

  const isoDateArr = dateSheets.map(ds => {
    const [dd, mm, yy] = ds.split('.');
    return `20${yy}-${mm}-${dd}`;
  });

  const statusEl = document.getElementById('escala-sp-status');
  const btnAuto  = document.getElementById('btn-escala-auto');
  if(statusEl){ statusEl.style.display=''; statusEl.style.background='#dbeafe'; statusEl.style.color='#1d4ed8'; statusEl.innerHTML=`⏳ Buscando escala para ${isoDateArr.length} data(s) — filial ${filial}...`; }
  if(btnAuto) btnAuto.disabled = true;

  try {
    let rows;
    if(!window._supa) throw new Error('supabaseClient não disponível');

    const { data, error } = await window._supa.rpc('get_escala_por_datas', {
      p_datas:  isoDateArr,
      p_filial: filial
    });

    if(error){
      // Fallback: query direta
      console.warn('[carregarEscalaPorDatasControle] RPC indisponível:', error.message);
      const { data: d2, error: e2 } = await window._supa
        .from('escala')
        .select('data_escala,placa,rota,motorista,auxiliar,status,tipo_escala')
        .in('data_escala', isoDateArr)
        .eq('filial', filial)
        .order('data_escala', { ascending: true })
        .order('placa',       { ascending: true })
        .limit(5000);
      if(e2) throw new Error(e2.message);
      rows = d2 || [];
    } else {
      rows = data || [];
    }

    if(!rows.length){
      if(statusEl){ statusEl.style.background='#fef3c7'; statusEl.style.color='#92400e'; statusEl.innerHTML=`⚠ Nenhum dado de escala encontrado para as datas do CONTROLE (filial: ${filial}).`; }
      if(btnAuto){ btnAuto.disabled=false; }
      return;
    }

    // Monta cache usando MESMAS strings de DIAS (sem risco de encoding)
    const GET_DAY_TO_DIAS = { 1:DIAS[0],2:DIAS[1],3:DIAS[2],4:DIAS[3],5:DIAS[4],6:DIAS[5] };
    const cacheByDay  = {};
    const cacheByDate = {};

    for(const row of rows){
      if(!row.placa || !row.data_escala) continue;
      const dt      = new Date(String(row.data_escala).substring(0,10) + 'T12:00:00');
      const dow     = dt.getDay();
      const dayName = GET_DAY_TO_DIAS[dow];
      if(!dayName) continue;

      const dd = String(dt.getDate()).padStart(2,'0');
      const mm = String(dt.getMonth()+1).padStart(2,'0');
      const yy = String(dt.getFullYear()).slice(-2);
      const ds = `${dd}.${mm}.${yy}`;

      const rotaRaw = row.rota;
      const entry   = {
        placa: String(row.placa     || '').trim().toUpperCase(),
        mot:   String(row.motorista || '').trim(),
        aux:   String(row.auxiliar  || '').trim(),
        rota:  rotaRaw !== null && rotaRaw !== undefined && rotaRaw !== ''
               ? (isNaN(Number(rotaRaw)) ? String(rotaRaw).trim() : Number(rotaRaw)) : null,
        stat:  String(row.status || '').trim()
      };
      if(!cacheByDay[dayName])  cacheByDay[dayName]  = [];
      cacheByDay[dayName].push(entry);
      if(!cacheByDate[ds]) cacheByDate[ds] = { dayName, rows:[] };
      cacheByDate[ds].rows.push(entry);
    }

    window._s3EscalaSupabase = cacheByDay;
    window._s3EscalaByDate   = cacheByDate;
    window._s3SemanaNome     = `Escala SP (${isoDateArr[0]} → ${isoDateArr[isoDateArr.length-1]})`;
    window._s3EscalaFilial   = filial;
    rotList = []; wb_rot = null;

    const total = rows.length;
    const datas = Object.keys(cacheByDate).sort();
    const dias  = [...new Set(datas.map(d => cacheByDate[d].dayName))];

    if(statusEl){
      statusEl.style.background = '#d1fae5';
      statusEl.style.color      = '#065f46';
      statusEl.innerHTML = `✓ Escala carregada — filial <strong>${filial}</strong> · ${total} linha(s) em ${datas.length} dia(s): ${dias.join(', ')}`;
    }
    if(btnAuto) btnAuto.disabled = false;
    if(wb_ctrl2) buildS3Mapping();

  } catch(e) {
    console.error('[carregarEscalaPorDatasControle]', e);
    if(statusEl){ statusEl.style.background='#fde8ec'; statusEl.style.color='#9b1c1c'; statusEl.innerHTML='✕ Erro: ' + e.message; }
    if(btnAuto) btnAuto.disabled = false;
  }
}

// Carrega as linhas da escala para a semana selecionada e monta o cache _s3EscalaSupabase
// Calcula as 7 datas ISO de uma semana usando a MESMA fórmula do escala.js
// Base: 28/12/2025 UTC (semana 1 = 29/12 seg a 04/01 dom... na verdade dom 28/12 a sab 03/01)
function calcDatasSemana(semanaNome){
  const match = semanaNome.match(/SEMANA\s+0*(\d+)/i);
  if(!match) return [];
  const weekNum  = parseInt(match[1]);
  const baseUTC  = Date.UTC(2025, 11, 28);           // 28 dez 2025 UTC (igual escala.js)
  const startUTC = baseUTC + (weekNum - 1) * 7 * 86400000;
  const dates    = [];
  for(let d = 0; d < 7; d++){
    const dt = new Date(startUTC + d * 86400000);
    dates.push(dt.toISOString().split('T')[0]);        // YYYY-MM-DD
  }
  return dates;
}

async function confirmarEscalaSupabase(){
  const sel        = document.getElementById('sel-semana-escala');
  const semanaNome = sel?.value;
  if(!semanaNome){ alert('Selecione uma semana.'); return; }

  // Filial: usa o select se disponível, senão cai para o usuário logado
  const filialSel = document.getElementById('sel-filial-escala')?.value?.trim();
  const filial    = filialSel || (JSON.parse(localStorage.getItem('usuarioLogado') || '{}').filial || '').trim();
  if(!filial){ alert('Selecione a Filial para carregar a escala.'); return; }

  // Calcula as datas reais da semana (mesma fórmula do escala.js)
  const isoDateArr = calcDatasSemana(semanaNome);
  if(!isoDateArr.length){ alert('Semana inválida: ' + semanaNome); return; }

  const statusEl = document.getElementById('escala-sp-status');
  const btnUsar  = document.getElementById('btn-usar-semana');
  if(statusEl){
    statusEl.style.display=''; statusEl.style.background='#dbeafe'; statusEl.style.color='#1d4ed8';
    statusEl.innerHTML=`⏳ Buscando escala — ${semanaNome} · filial ${filial} · datas ${isoDateArr[1]} → ${isoDateArr[6]}...`;
  }
  if(btnUsar) btnUsar.disabled = true;

  try {
    let rows;
    if(!window._supa) throw new Error('supabaseClient não disponível');

    // Busca pelas datas calculadas (não pelo semana_nome — ignora label do banco)
    const { data, error } = await window._supa.rpc('get_escala_por_datas', {
      p_datas:  isoDateArr,
      p_filial: filial
    });

    if(error){
      console.warn('[confirmarEscalaSupabase] RPC indisponível, tentando query direta:', error.message);
      const { data: d2, error: e2 } = await window._supa
        .from('escala')
        .select('data_escala,placa,rota,motorista,auxiliar,status,tipo_escala')
        .in('data_escala', isoDateArr)
        .eq('filial', filial)
        .order('data_escala', { ascending: true })
        .order('placa',       { ascending: true })
        .limit(2000);
      if(e2) throw new Error(e2.message);
      rows = d2 || [];
    } else {
      rows = data || [];
    }

    if(!rows.length){
      if(statusEl){ statusEl.style.background='#fef3c7'; statusEl.style.color='#92400e'; statusEl.innerHTML=`⚠ Sem dados de escala para ${semanaNome} (${isoDateArr[1]} → ${isoDateArr[6]}) · filial ${filial}.`; }
      if(btnUsar){ btnUsar.disabled=false; btnUsar.style.opacity='1'; }
      return;
    }

    // Usa os mesmos nomes de DIAS definidos globalmente (garantia de encoding idêntico)
    // DIAS = ['SEGUNDA','TERÇA','QUARTA','QUINTA','SEXTA','SABADO']
    // getDay(): 0=Dom,1=Seg,2=Ter,3=Qua,4=Qui,5=Sex,6=Sáb
    const GET_DAY_TO_DIAS = { 1:DIAS[0],2:DIAS[1],3:DIAS[2],4:DIAS[3],5:DIAS[4],6:DIAS[5] };

    const cacheByDay  = {};   // { 'SEGUNDA': [...], 'TERÇA': [...], ... }
    const cacheByDate = {};   // { 'DD.MM.YY': [...] }  ← lookup por data exata do CONTROLE

    for(const row of rows){
      if(!row.placa || !row.data_escala) continue;

      // Usa T12:00:00 para evitar problemas de timezone
      const dt  = new Date(row.data_escala + 'T12:00:00');
      const dow = dt.getDay();                       // 0=Dom…6=Sáb
      const dayName = GET_DAY_TO_DIAS[dow];
      if(!dayName) continue;                          // ignora domingo e inválidos

      // Chave formato DD.MM.YY (mesma que o CONTROLE usa nas abas)
      const dd  = String(dt.getDate()).padStart(2,'0');
      const mm  = String(dt.getMonth()+1).padStart(2,'0');
      const yy  = String(dt.getFullYear()).slice(-2);
      const dsMM = `${dd}.${mm}.${yy}`;

      const rotaRaw = row.rota;
      const entry   = {
        placa: String(row.placa       || '').trim().toUpperCase(),
        mot:   String(row.motorista   || '').trim(),
        aux:   String(row.auxiliar    || '').trim(),
        rota:  rotaRaw !== null && rotaRaw !== undefined && rotaRaw !== ''
               ? (isNaN(Number(rotaRaw)) ? String(rotaRaw).trim() : Number(rotaRaw))
               : null,
        stat:  String(row.status || '').trim()
      };

      if(!cacheByDay[dayName]) cacheByDay[dayName] = [];
      cacheByDay[dayName].push(entry);

      if(!cacheByDate[dsMM]) cacheByDate[dsMM] = { dayName, rows:[] };
      cacheByDate[dsMM].rows.push(entry);
    }

    window._s3EscalaSupabase  = cacheByDay;
    window._s3EscalaByDate    = cacheByDate;
    window._s3SemanaNome      = semanaNome;
    window._s3EscalaFilial    = filial;
    rotList = []; wb_rot = null;

    const totalVeiculos = Object.values(cacheByDay).reduce((s, a) => s + a.length, 0);
    const datas = Object.keys(cacheByDate).sort();
    const dias  = [...new Set(datas.map(d => cacheByDate[d].dayName))];
    // Mostra datas calculadas (SEGUNDA a SABADO) para o usuário confirmar
    const seg = isoDateArr[1], sab = isoDateArr[6];
    const fmt = iso => { const [y,m,d]=iso.split('-'); return `${d}.${m}.${y.slice(-2)}`; };
    const rangeStr = ` (${fmt(seg)} → ${fmt(sab)})`;

    if(statusEl){
      statusEl.style.background = '#d1fae5';
      statusEl.style.color      = '#065f46';
      statusEl.innerHTML = `✓ <strong>${semanaNome}</strong> · filial <strong>${filial}</strong>${rangeStr} — ${totalVeiculos} veículo(s) em ${dias.length} dia(s): ${dias.join(', ')}`;
    }
    if(btnUsar){ btnUsar.disabled=false; btnUsar.style.opacity='1'; }

    // Dispara remapeamento se o CONTROLE já estiver carregado
    if(wb_ctrl2) buildS3Mapping();

  } catch(e) {
    console.error('[confirmarEscalaSupabase]', e);
    if(statusEl){ statusEl.style.background='#fde8ec'; statusEl.style.color='#9b1c1c'; statusEl.innerHTML='✕ Erro ao carregar escala: ' + e.message; }
    if(btnUsar){ btnUsar.disabled=false; btnUsar.style.opacity='1'; }
  }
}

function getDateData(wb,sheetName){
  const map={};const ws=(wb&&wb.Sheets)?wb.Sheets[sheetName]:null;if(!ws&&typeof s1Rows==='undefined')return map;if(ws){
  const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});
  // Find data start: skip header rows (row with N°FOLHA/NOME, date rows, etc.)
  let dataStart=3;
  for(let i=0;i<Math.min(rows.length,6);i++){
    const n=norm(rows[i][1]);
    if(n&&n!=='NOME'&&!n.startsWith('N°')&&!n.startsWith('N ')&&!/^\d{2}\//.test(n)&&!/^\d{2}\.\d{2}\./.test(n)){
      dataStart=i;break;
    }
  }
  for(let i=dataStart;i<rows.length;i++){
    const nome=norm(rows[i][1]);
    if(!nome||nome==='NOME')continue;
    const saida=String(rows[i][2]||'').trim();
    const entrada=String(rows[i][3]||'').trim();
    map[nome]={saida:saida||'SEM REGISTRO',entrada:entrada||'SEM REGISTRO'};
  }

  } // end if(ws)

  // ── Enrich with s1Rows (ponto processado no Passo 1) ──
  // s1Rows has {nome(nome_ponto), saida, entrada, dataAba}
  // dataAba format: "20.04.26" — sheetName format varies
  if(typeof s1Rows!=='undefined'&&s1Rows.length){
    // Parse sheetName to get date "dd.mm.yy"
    const parts=sheetName.split('.');
    const abaKey=sheetName; // already in dd.mm.yy
    const matching=s1Rows.filter(r=>r.dataAba===abaKey);
    for(const r of matching){
      const nomePonto=norm(r.nome);
      // Only overwrite if not already in map from xlsx
      if(!map[nomePonto]||map[nomePonto].saida==='SEM REGISTRO'){
        map[nomePonto]={saida:r.saida||'SEM REGISTRO',entrada:r.entrada||'SEM REGISTRO'};
      }
    }
  }

  return map;
}
function getEscala(wb,dayName,ds){
  // ── Fonte prioritária 1: lookup por data exata (evita problema de semana/encoding) ──
  if(ds && window._s3EscalaByDate?.[ds]?.rows?.length) {
    return window._s3EscalaByDate[ds].rows;
  }
  // ── Fonte prioritária 2: lookup por nome do dia ──
  const supa = window._s3EscalaSupabase;
  if(supa && supa[dayName] && supa[dayName].length) return supa[dayName];

  // ── Fallback: xlsx ──
  const result=[];
  if(!wb) return result;
  let ws=wb.Sheets[dayName];
  if(!ws){const found=wb.SheetNames.find(s=>s.trim().toUpperCase()===dayName);if(found)ws=wb.Sheets[found];}
  if(!ws)return result;
  const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});
  let hdr=0;
  for(let i=0;i<Math.min(rows.length,12);i++){
    const u=rows[i].map(v=>norm(v));
    // Require PLACA + MOTORISTA + AUXILIAR all present (avoids partial header rows)
    if(u.some(v=>v==='PLACA')&&u.some(v=>v==='MOTORISTA')&&u.some(v=>v==='AUXILIAR')){hdr=i;break;}
    // Fallback: partial match
    if(i>=9&&u.some(v=>v.includes('PLACA'))&&u.some(v=>v.includes('MOTORISTA'))){hdr=i;break;}
  }
  const hdrs=rows[hdr].map(v=>norm(v));
  const ci=n=>{
    let idx=hdrs.indexOf(n);
    if(idx>=0)return idx;
    return hdrs.findIndex(h=>h.includes(n));
  };
  // For ROTEIRO SP: PLACA=col2(B), ROTA=col3(C), STAT=col4(D), MOTORISTA=col5(E), AUXILIAR=col6(F) — 0-indexed
  const iP=ci('PLACA'),iR=ci('ROTA'),iS=ci('STAT');
  // MOTORISTA comes BEFORE AUXILIAR — take first occurrence of each
  const allMotIdx=hdrs.reduce((a,h,i)=>{if(h==='MOTORISTA')a.push(i);return a;},[]);
  const allAuxIdx=hdrs.reduce((a,h,i)=>{if(h==='AUXILIAR')a.push(i);return a;},[]);
  const iM=allMotIdx[0]??hdrs.findIndex(h=>h.includes('MOTORISTA'));
  const iA=allAuxIdx[0]??hdrs.findIndex(h=>h.includes('AUXILIAR'));
  const SKIP=['TRANSFERENCIA','RESERVAS','FALTAS','AFASTADOS','EQUIPAMENTO','FÉRIAS','FERIAS'];
  for(let i=hdr+1;i<rows.length;i++){
    const r=rows[i];
    const placa=String(r[iP]||'').trim();
    if(!placa||placa==='PLACA')continue; // skip blanks and repeated headers
    const allStr=r.map(v=>String(v||'')).join(' ').toUpperCase();
    if(SKIP.some(k=>allStr.includes(k)))continue;
    const mot=String(r[iM]||'').trim(),aux=String(r[iA]||'').trim();
    if(!mot&&!aux)continue;
    if(mot==='MOTORISTA'&&aux==='AUXILIAR')continue; // skip repeated header rows
    const rotaRaw=r[iR];
    const rota=rotaRaw!==undefined&&rotaRaw!==null&&rotaRaw!==''?(isNaN(Number(rotaRaw))?String(rotaRaw).trim():Number(rotaRaw)):null;
    result.push({placa,rota,stat:String(r[iS]||'').trim(),mot,aux});
  }
  // 🔧 DEDUP: remove linhas idênticas do roteiro (mesmo veículo listado 2x+).
  // Chave: placa + rota + motorista + auxiliar. Mantém a 1ª ocorrência.
  const seen = new Set();
  const deduped = [];
  let dupCount = 0;
  for(const e of result){
    const key = [
      String(e.placa||'').toUpperCase().trim(),
      String(e.rota||'').trim(),
      norm(e.mot),
      norm(e.aux)
    ].join('|');
    if(seen.has(key)){ dupCount++; continue; }
    seen.add(key);
    deduped.push(e);
  }
  if(dupCount > 0){
    console.warn(`[getEscala ${dayName}] ${dupCount} linha(s) duplicada(s) removida(s) do roteiro`);
  }
  return deduped;
}
function calcInterj(s,e){
  if(isSpec(s)||isSpec(e))return'SEM REGISTRO';
  const ts=parseHHMM(s),te=parseHHMM(e);if(!ts||!te)return'SEM REGISTRO';
  let m=(te.h*60+te.m)-(ts.h*60+ts.m);if(m<=0)m+=1440;
  return`${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`;
}
function gerarObs(s,e,ij){
  const p=[];
  // Saída: se for motivo legítimo (FOLGA/FÉRIAS/INSS/etc) usa o motivo; se vazio/NaN, trata como sem registro
  const reasonS = getAbsenceReason(s);
  if(reasonS){
    p.push(reasonS);
  } else if(isSpec(s)){
    p.push('SEM REGISTRO SAÍDA');
  } else {
    const t=parseHHMM(s);
    if(t&&(t.h>19||(t.h===19&&t.m>20))) p.push('SAÍDA APÓS 19:20');
  }
  // Entrada: mesma lógica — motivo legítimo NÃO duplica se já listado pela saída
  const reasonE = getAbsenceReason(e);
  if(reasonE){
    if(reasonE !== reasonS) p.push(reasonE);
  } else if(isSpec(e)){
    // Se a saída já justificou (folga/férias/etc), entrada vazia faz sentido — não duplica
    if(!reasonS) p.push('SEM REGISTRO ENTRADA');
  } else {
    const t=parseHHMM(e);
    if(t&&(t.h<6||(t.h===6&&t.m<45))) p.push('ENTRADA ANTES 06:45');
  }
  // Interjornada só importa se ambas as pontas são horários reais
  if(ij!=='SEM REGISTRO'&&ij && !reasonS && !reasonE){
    const t=parseHHMM(ij);
    if(t&&(t.h*60+t.m)<660) p.push('INTERJORNADA < 11H');
  }
  return p.length?p.join(' | '):'OK';
}

function buildS3XLSX(){
  const bin=XLSX.write(wb_ctrl2,{type:'array',bookType:'xlsx',cellFormula:true});
  const wb=XLSX.read(bin,{type:'array',cellFormula:true});
  for(const[day,rows]of Object.entries(s3Results)){
    if(!rows.length)continue;
    const rName='RESUMO '+day;
    const idx=wb.SheetNames.indexOf(rName);
    if(idx>=0){wb.SheetNames.splice(idx,1);delete wb.Sheets[rName];}
    // Single clean header row — PLACA in col A, rest follow
    const data=[
      ['PLACA','CIDADE','ROTA','STAT','MOTORISTA','TEL MOTORISTA','SAÍDA MOTORISTA','ENTRADA MOTORISTA','INTERJORNADA MOTORISTA','OBSERVAÇÃO MOTORISTA','AUXILIAR','TEL AUXILIAR','SAÍDA AUXILIAR','ENTRADA AUXILIAR','INTERJORNADA AUXILIAR','OBSERVAÇÃO AUXILIAR'],
      ...rows.map(r=>[r.placa,r.cidade||'',r.rota,r.stat,r.mot,r.tel_m||'',r.saida_m,r.entrada_m,r.interj_m,r.obs_m,r.aux,r.tel_a||'',r.saida_a,r.entrada_a,r.interj_a,r.obs_a])
    ];
    const ws=XLSX.utils.aoa_to_sheet(data);
    ws['!cols']=[{wch:22},{wch:28},{wch:6},{wch:10},{wch:30},{wch:10},{wch:10},{wch:12},{wch:36},{wch:30},{wch:10},{wch:10},{wch:12},{wch:36}];
    wb.SheetNames.push(rName);wb.Sheets[rName]=ws;
  }
  return XLSX.write(wb,{type:'array',bookType:'xlsx',cellFormula:true});
}

