// ═══════════════════════════════════════════════════════
//  SUPABASE — TRATATIVAS / AÇÕES
// ═══════════════════════════════════════════════════════
function cdjToISODateBR(value){
  const s=String(value||'').trim();
  let m=s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if(m) return `${m[3]}-${m[2]}-${m[1]}`;
  m=s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if(m) return s;
  return '';
}
function cdjFromISODate(value){
  const s=String(value||'');
  const m=s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  return m ? `${m[3]}/${m[2]}/${m[1]}` : s;
}
function cdjNorm(v){
  return String(v||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim().toUpperCase();
}

function cdjSimpleHash(value){
  const str = String(value||'');
  let h = 2166136261;
  for(let i=0;i<str.length;i++){
    h ^= str.charCodeAt(i);
    h += (h<<1) + (h<<4) + (h<<7) + (h<<8) + (h<<24);
  }
  return ('00000000' + (h>>>0).toString(16)).slice(-8);
}
function buildActionOrigemLocalId(actionObj, row){
  // ID determinístico da tratativa por infração.
  // Regra de produção: no mesmo dia + placa + colaborador, a ação nova SUBSTITUI a anterior.
  // Não usamos o tipo da ação no ID; assim LIGAÇÃO -> OK atualiza a mesma tratativa em vez de duplicar.
  const base = [
    cdjToISODateBR(actionObj?.data_infracao || row?._date || row?.data_ref || ''),
    cdjNorm(actionObj?.placa || row?.placa || ''),
    cdjNorm(actionObj?.nome || row?.nome || row?.colaborador || '')
  ].join('|');
  return 'acao_' + cdjSimpleHash(base) + '_' + cdjSimpleHash(base.split('').reverse().join(''));
}
function buildLinhaHash(r, i){
  return 'linha_' + cdjSimpleHash([
    r?._date || r?.data_ref || '', r?.placa || '', r?.rota || '', r?.stat || '',
    r?.role || r?.funcao || '', r?.nome || r?.colaborador || '', r?.saida || '',
    r?.entrada || '', r?.interj || '', i
  ].join('|'));
}
function actionToTratativaDb(actionText){
  const s = cdjNorm(actionText);
  if(s.includes('LIGAC')) return {tipo:'LIGACAO', nivel:null};
  if(s.includes('ADVERTENCIA') && s.includes('VERBAL')){
    const nivel = s.includes('3') ? 3 : (s.includes('2') ? 2 : 1);
    return {tipo:'ADVERTENCIA_VERBAL', nivel};
  }
  if(s.includes('ADVERTENCIA') && s.includes('ESCRITA')){
    const nivel = s.includes('3') ? 3 : (s.includes('2') ? 2 : 1);
    return {tipo:'ADVERTENCIA_ESCRITA', nivel};
  }
  if(s.includes('SUSPEN')) return {tipo:'SUSPENSAO', nivel:null};
  if(s.includes('GERENCIA')) return {tipo:'AC_GERENCIA', nivel:null};
  if(s === 'OK' || s.includes(' OK')) return {tipo:'OK', nivel:null};
  if(!String(actionText||'').trim()) return {tipo:'SEM_TRATATIVA', nivel:null};
  return {tipo:'OUTRA', nivel:null};
}
function buildTratativaPayload(actionObj, linhaId){
  const session = sbGetSession ? sbGetSession() : null;
  const mapped = actionToTratativaDb(actionObj?.acao || actionObj?.tipo || '');
  return {
    analise_linha_id: linhaId,
    tipo: mapped.tipo,
    nivel: mapped.nivel,
    status: 'CONCLUIDA',
    observacao: actionObj?.observacao || null,
    recomendacao_sistema: actionObj?.acao || null,
    origem_local_id: actionObj?.client_uid || actionObj?.origem_local_id || buildActionOrigemLocalId(actionObj),
    created_by: session?.user?.id || null,
    updated_by: session?.user?.id || null
  };
}
async function findLatestAnaliseIdForDate(dateISO){
  if(!supabaseAvailable() || !dateISO) return null;
  const resp = await sbFetch(`/rest/v1/analises_jornada?select=id&tipo=eq.DIA&data_inicio=eq.${encodeURIComponent(dateISO)}&order=updated_at.desc&limit=1`);
  if(!resp.ok) return null;
  const arr = await resp.json();
  return arr?.[0]?.id || null;
}
async function findSupabaseLinhaIdForRow(row){
  if(row?._supabase_linha_id) return row._supabase_linha_id;
  if(!supabaseAvailable()) return null;
  const dateISO = cdjToISODateBR(cdjRowDateBR(row));
  const analiseId = row?._supabase_analise_id || window.cdjAnaliseSupabaseAtualId || await findLatestAnaliseIdForDate(dateISO);
  if(!analiseId) return null;
  const placa = String(row?.placa||'').trim();
  let url = `/rest/v1/analise_linhas?select=id,nome,colaborador,placa,data_ref,linha_origem&analise_id=eq.${encodeURIComponent(analiseId)}&limit=1000`;
  if(placa) url += `&placa=eq.${encodeURIComponent(placa)}`;
  const resp = await sbFetch(url);
  if(!resp.ok) return null;
  const lines = await resp.json();
  const targetName = cdjNorm(row?.nome || row?.colaborador || '');
  const targetDate = dateISO;
  let found = lines.find(l => cdjNorm(l.nome || l.colaborador) === targetName && (!targetDate || String(l.data_ref||'') === targetDate));
  if(!found) found = lines.find(l => cdjNorm(l.nome || l.colaborador) === targetName);
  if(!found) found = lines[0];
  return found?.id || null;
}
// ☁ Garante que existe uma análise do dia (data do row) na nuvem.
// Constrói um snapshot a partir de s4Rows (linhas em memória da tela atual)
// e chama supabaseUpsertAnaliseDia. Idempotente — se o dia já existir,
// faz apenas merge (upsert) das linhas.
async function ensureSupabaseAnaliseForRow(row){
  if(!supabaseAvailable()) return null;
  const dateBR = cdjRowDateBR(row);
  if(!dateBR || !/^\d{2}\/\d{2}\/\d{4}$/.test(dateBR)){
    throw new Error('Data do registro inválida — não foi possível subir para nuvem.');
  }
  if(!Array.isArray(s4Rows) || !s4Rows.length){
    throw new Error('Resumo da tela vazio — abra o dia no Passo 4 antes de salvar a ação.');
  }
  const rowsDoDia = s4Rows.filter(r => r._date === dateBR);
  if(!rowsDoDia.length){
    throw new Error('Nenhuma linha na tela para a data desta ação.');
  }
  const dtObj = parseDateBR(dateBR);
  const iso = dtObj ? isoWeek(dtObj) : null;
  const snap = {
    id: `day_${dateBR.replace(/\//g,'-')}`,
    tipo: 'DIA',
    kind: 'day',
    nome: `Análise do dia ${dateBR}`,
    data_ref: dateBR,
    datas: [dateBR],
    iso_year: iso?.year || null,
    iso_week: iso?.week || null,
    iso_key:  iso ? isoWeekKey(iso.year, iso.week) : null,
    sheet: document.getElementById('s4-sheet-sel')?.value || '',
    salvo_em: new Date().toISOString(),
    rows: rowsDoDia,
    actions: [],
    salvo_nuvem: false
  };
  const saved = await supabaseUpsertAnaliseDia(snap);
  // Persiste local também para futuras ações neste dia.
  try{
    snap.supabase_id = saved.id;
    snap.salvo_nuvem = true;
    await dbPut('daily_analyses', snap);
  }catch(e){ /* não fatal */ }
  return saved;
}

async function saveActionSupabase(actionObj, row){
  const session = await cdjEnsureSupabaseSession();
  if(!session?.user?.id || !session?.access_token) throw new Error('Sessão Supabase não encontrada. Faça login novamente.');
  if(row && !row._date && actionObj?.data_infracao) row._date = cdjDateBRFromAny(actionObj.data_infracao);
  let linhaId = await findSupabaseLinhaIdForRow(row);

  // ☁ AUTO-UPLOAD: se a linha ainda não existe na nuvem, construímos um
  // snapshot do dia atual a partir de s4Rows e replicamos para o Supabase
  // automaticamente — assim qualquer usuário pode salvar ações sem precisar
  // clicar em "Salvar Dia" manualmente. (Antes a ação ficava só no IndexedDB
  // local e não subia para o banco compartilhado.)
  if(!linhaId){
    try{
      await ensureSupabaseAnaliseForRow(row);
      linhaId = await findSupabaseLinhaIdForRow(row);
    }catch(e){
      console.warn('[ensureSupabaseAnaliseForRow]', e);
    }
  }
  if(!linhaId) throw new Error('Não consegui localizar a linha no banco. Tente "Salvar Dia" manualmente.');
  const payload = [buildTratativaPayload(actionObj, linhaId)];
  const resp = await sbFetch('/rest/v1/tratativas?on_conflict=analise_linha_id,origem_local_id', {
    method:'POST',
    headers:{'Prefer':'resolution=merge-duplicates,return=representation'},
    body: JSON.stringify(payload)
  });
  if(!resp.ok) throw new Error(await resp.text());
  const saved = (await resp.json())[0];
  actionObj.supabase_tratativa_id = saved?.id || null;
  actionObj.supabase_linha_id = linhaId;
  return saved;
}
async function syncLocalActionsForAnalise(item, savedAnalise){
  if(!supabaseAvailable() || !savedAnalise?.id) return;
  let acts=[];
  try{ acts = await dbGetAll('actions'); }catch(e){ acts=[]; }
  if(!acts.length) return;
  const resp = await sbFetch(`/rest/v1/analise_linhas?select=id,nome,colaborador,placa,data_ref,linha_origem&analise_id=eq.${encodeURIComponent(savedAnalise.id)}&limit=5000`);
  if(!resp.ok) return;
  const lines = await resp.json();
  const payload=[];
  for(const a of acts){
    const ad = cdjToISODateBR(a.data_infracao || '');
    // Sem data de infração a ação é ambígua; não sincroniza automaticamente para evitar vínculo no dia errado.
    if(!ad) continue;
    if(!a.client_uid && !a.origem_local_id) a.client_uid = buildActionOrigemLocalId(a);
    const line = lines.find(l =>
      cdjNorm(l.nome||l.colaborador) === cdjNorm(a.nome) &&
      String(l.placa||'').trim() === String(a.placa||'').trim() &&
      String(l.data_ref||'') === ad
    );
    if(line?.id) payload.push(buildTratativaPayload(a, line.id));
  }
  if(!payload.length) return;
  for(let i=0;i<payload.length;i+=300){
    const lote=payload.slice(i,i+300);
    const ins = await sbFetch('/rest/v1/tratativas?on_conflict=analise_linha_id,origem_local_id', {
      method:'POST',
      headers:{'Prefer':'resolution=merge-duplicates,return=minimal'},
      body: JSON.stringify(lote)
    });
    if(!ins.ok) console.warn('[syncLocalActionsForAnalise]', await ins.text());
  }
}


function sameActionNaturalKey(a){
  return [
    cdjToISODateBR(a?.data_infracao || ''),
    cdjNorm(a?.placa || ''),
    cdjNorm(a?.nome || ''),
    cdjNorm(a?.acao || a?.tipo || '')
  ].join('|');
}
function sameInfractionNaturalKey(a){
  return [
    cdjToISODateBR(a?.data_infracao || ''),
    cdjNorm(a?.placa || ''),
    cdjNorm(a?.nome || '')
  ].join('|');
}
async function dedupeLocalActionsExact(){
  let acts=[];
  try{ acts = await dbGetAll('actions'); }catch(e){ return 0; }
  if(!acts.length) return 0;
  const keep = new Map();
  const del=[];
  for(const a of acts){
    const key = a.client_uid || a.origem_local_id || sameInfractionNaturalKey(a);
    if(!key || key==='||') continue;
    const prev = keep.get(key);
    if(!prev){ keep.set(key,a); continue; }
    // Mantém o registro mais recente, remove o outro.
    const prevTime = new Date(prev.ts || prev.timestamp || 0).getTime() || 0;
    const curTime  = new Date(a.ts || a.timestamp || 0).getTime() || 0;
    if(curTime >= prevTime){ del.push(prev); keep.set(key,a); }
    else del.push(a);
  }
  for(const a of del){ if(a?.id !== undefined) await dbDelete('actions', a.id); }
  return del.length;
}

async function saveAction(){
  if(!modalRow){closeModal();return;}
  const action=document.getElementById('modal-action-sel').value;
  const obs=document.getElementById('modal-obs').value||'';
  if(!obs.trim()){
    alert('Por favor, preencha a justificativa na observação.');
    return;
  }
  const dateInf=document.getElementById('modal-date-inf').value||'';
  const now=new Date();
  const actionObj={
    ts:now.toISOString(),
    timestamp:now.toLocaleString('pt-BR'),
    placa:modalRow.placa||'',
    rota:modalRow.rota||'',
    stat:modalRow.stat||'',
    nome:modalRow.nome||'',
    role:modalRow.role||'',
    acao:action,
    observacao:obs,
    data_infracao:dateInf,
    data_acao:now.toLocaleDateString('pt-BR'),
    hora_acao:now.toLocaleTimeString('pt-BR')
  };
  actionObj.client_uid = buildActionOrigemLocalId(actionObj, modalRow);

  // Evita duplicidade local: mesma data + placa + colaborador atualiza a tratativa existente.
  // Ex.: se registrou LIGAÇÃO e depois OK na mesma infração, fica apenas OK como ação atual.
  await dedupeLocalActionsExact();
  const existingActs = await dbGetAll('actions');
  const sameKey = sameInfractionNaturalKey(actionObj);
  const existing = existingActs.find(a => (a.client_uid === actionObj.client_uid) || sameInfractionNaturalKey(a) === sameKey);
  if(existing && existing.id !== undefined){
    actionObj.id = existing.id;
    await dbPut('actions', actionObj);
  }else{
    await dbAdd('actions', actionObj);
  }

  let nuvemOk=false, nuvemMsg='';
  try{
    if(typeof saveActionSupabase === 'function'){
      await saveActionSupabase(actionObj, modalRow);
      nuvemOk=true;
    }
  }catch(e){
    console.warn('[Supabase saveAction]', e);
    nuvemMsg = e.message || String(e);
  }

  closeModal();
  updateActionsBadge();
  renderS4Table();
  refreshDashboard();

  if(nuvemOk) alert('✓ Ação salva localmente e no banco de dados (visível para todos os usuários).');
  else alert('✓ Ação salva localmente.\n' + (nuvemMsg ? '⚠ Nuvem: ' + nuvemMsg + '\n' : '') + 'Clique em "Salvar Dia" e a ação subirá no próximo sincronismo.');
}
async function modalRemoveLast(){
  if(!modalRow)return;
  const acts=await dbGetAll('actions');
  const mine=acts.filter(a=>a.placa===modalRow.placa&&a.nome===modalRow.nome);
  if(!mine.length){alert('Nenhuma ação para remover.');return;}
  const last=mine.slice().reverse()[0];
  if(!confirm(`Remover: ${last.acao} — ${last.timestamp}?`))return;
  await dbDelete('actions',last.id);
  closeModal();renderS4Table();updateActionsBadge();
}

