async function savePhone(){
  const nomeDisplay=document.getElementById('phone-nome-inp').value.trim();
  const tel=document.getElementById('phone-tel-inp').value.trim();
  const obs=document.getElementById('phone-obs-inp').value.trim();
  if(!tel){alert('Informe o numero de WhatsApp.');return;}

  let funcionarioUpdated=false;
  if(phoneModalRow){
    const func = phoneModalRow._wa_funcionario || await findFuncionarioForWhatsApp(phoneModalRow);
    if(func){
      phoneModalRow._wa_funcionario = func;
      const field = phoneModalRow._wa_phone_field || (confirm(
        `Salvar este numero no cadastro de ${func.nome_completo || func.nome}?\n\nOK = Contato Corporativo\nCancelar = Contato Pessoal`
      ) ? 'contato_corp' : 'contato_pessoal');
      funcionarioUpdated = await updateFuncionarioWhatsApp(func.id, field, tel);
      if(funcionarioUpdated){
        func[field] = tel;
        phoneModalRow.telefone = tel;
      }
    }else if(confirm('Nao encontrei este colaborador na tabela de funcionarios.\n\nDeseja abrir o cadastro de funcionarios para cadastrar o contato?')){
      window.open('funcionario.html', '_blank');
    }
  }

  await dbSavePhone(nomeDisplay,tel,obs);
  if(phoneModalRow){
    const nomeAbrev=(phoneModalRow.nome||'').trim();
    if(nomeAbrev && norm(nomeAbrev)!==norm(nomeDisplay)){
      await dbSavePhone(nomeAbrev,tel,obs);
    }
  }
  const rowForWhatsApp = phoneModalRow;
  closePhoneModal();
  renderS4Table();
  if(funcionarioUpdated) alert('Contato salvo no cadastro do funcionario.');
  openWhatsApp(nomeDisplay,tel,rowForWhatsApp);
}

async function handleWaClick(row){
  const variants = waNameVariants(row);
  const nomeDisplay = variants[0] || row.nome || '';

  const func = await findFuncionarioForWhatsApp(row);
  if(func){
    row._wa_funcionario = func;
    const chosen = chooseWhatsAppContact(func);
    if(chosen?.tel){
      row.telefone = chosen.tel;
      await dbSavePhone(nomeDisplay, chosen.tel, `Funcionario: ${chosen.label}`).catch(()=>{});
      openWhatsApp(nomeDisplay, chosen.tel, row);
      return;
    }
    row._wa_phone_field = confirm(
      `${func.nome_completo || func.nome} nao possui contato corporativo nem pessoal preenchido.\n\n` +
      `Deseja cadastrar agora como Contato Corporativo?\n\nOK = Corporativo\nCancelar = Pessoal`
    ) ? 'contato_corp' : 'contato_pessoal';
    openPhoneModal(row);
    return;
  }

  if(row.telefone){
    openWhatsApp(nomeDisplay,row.telefone,row);
    return;
  }
  for(const v of variants){
    const t=getTelFromCad(v);
    if(t){openWhatsApp(nomeDisplay,t,row);return;}
  }
  for(const v of variants){
    const rec=await dbGetPhone(v);
    if(rec&&rec.tel){openWhatsApp(nomeDisplay,rec.tel,row);return;}
  }
  openPhoneModal(row);
}

function toProperFirstName(nomeCompleto){
  if(!nomeCompleto) return '';
  const first = String(nomeCompleto).trim().split(/\s+/)[0] || '';
  if(!first) return '';
  return first.charAt(0).toUpperCase() + first.slice(1).toLowerCase();
}

// Identifica os tipos de ocorrência a partir do obs (status)
function detectOcorrencias(obs){
  const o = String(obs||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toUpperCase();
  // Motivos legítimos: não geram alertas/WhatsApp
  const isAbsence = /^(FOLGA|FERIAS|FERIADO|FALTA|FALTOU|INSS|ATESTADO|ATEST\.|ABONADO|CARCERE|LICEN[CÇ]A)/i.test(o);
  if(isAbsence){
    return { semRegSaida:false, semRegEntrada:false, semRegistro:false, interjornada:false, absence:true };
  }
  return {
    semRegSaida:    o.includes('SEM REGISTRO SAIDA') || (o.includes('SEM REGISTRO') && o.includes('SAIDA')),
    semRegEntrada:  o.includes('SEM REGISTRO ENTRADA') || (o.includes('SEM REGISTRO') && o.includes('ENTRADA')),
    semRegistro:    o.includes('SEM REGISTRO') && !o.includes('SAIDA') && !o.includes('ENTRADA'),
    interjornada:   o.includes('INTERJORNADA') || o.includes('< 11') || o.includes('<11'),
    absence: false
  };
}

function buildWhatsAppMessage(nome, row){
  const nomeCompleto = row?.nomePonto || nome || '';
  const primeiroNome = toProperFirstName(nomeCompleto);
  const status   = row ? (row.obs || '') : '';
  const date     = row ? (row._date || '') : '';
  const oc = detectOcorrencias(status);
  const dataAbrev = date || '';
  let dataEntrada = dataAbrev;
  {
    const m = String(dataAbrev).match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
    if(m){
      const y = m[3].length===2 ? 2000+parseInt(m[3]) : parseInt(m[3]);
      const d = new Date(y, parseInt(m[2])-1, parseInt(m[1]));
      d.setDate(d.getDate()+1);
      dataEntrada = `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${String(d.getFullYear()).slice(-2)}`;
    }
  }
  let msg = `Olá ${primeiroNome || 'colaborador(a)'}, tudo bem? `;
  if(oc.semRegSaida && oc.semRegEntrada){
    msg += `Notamos que não houve registro de ponto nos horários de saída ${dataAbrev} e horários de entrada dia ${dataEntrada}. Poderia nos contar o que aconteceu?`;
  } else if(oc.semRegSaida){
    msg += `Notamos que não houve registro de ponto nos horários de saída dia ${dataAbrev}. Poderia nos contar o que aconteceu?`;
  } else if(oc.semRegEntrada){
    msg += `Notamos que não houve registro de ponto nos horários de entrada dia ${dataAbrev}. Poderia nos contar o que aconteceu?`;
  } else if(oc.semRegistro){
    msg += `Notamos que não houve registro de ponto no dia ${dataAbrev}. Poderia nos contar o que aconteceu?`;
  } else if(oc.interjornada){
    msg += `Notamos que o descanso entre jornadas no dia ${dataAbrev} ficou abaixo de 11 horas. Poderia nos contar o que aconteceu?`;
  } else {
    msg += `Notamos uma ocorrência no registro de ponto do dia ${dataAbrev}. Poderia nos contar o que aconteceu?`;
  }
  return msg;
}

function openWhatsApp(nome,tel,row){
  const digits=formatPhone(tel);
  if(!digits){alert('Número inválido: '+tel);return;}
  const msg = buildWhatsAppMessage(nome, row);
  const encoded = encodeURIComponent(msg);
  // Prioridade: web.whatsapp.com/send (WhatsApp Web direto, geralmente não bloqueado)
  // Fallback: wa.me (que redireciona para api.whatsapp.com — pode ser bloqueado por proxy)
  const provider = lsGet('wa_provider', 'web'); // 'web' | 'wame' | 'copy'
  if(provider === 'copy'){
    copyWhatsAppText(digits, msg);
    return;
  }
  const url = provider === 'wame'
    ? `https://wa.me/${digits}?text=${encoded}`
    : `https://web.whatsapp.com/send?phone=${digits}&text=${encoded}`;
  const win = window.open(url, '_blank');
  // Detecta se a aba foi bloqueada (popup blocker) ou se vai falhar
  if(!win){
    if(confirm('Não foi possível abrir o WhatsApp.\n\nDeseja COPIAR o telefone e a mensagem para colar manualmente no WhatsApp?')){
      copyWhatsAppText(digits, msg);
    }
  }
}

function copyWhatsAppText(digits, msg){
  const txt = `Telefone: +${digits}\n\nMensagem:\n${msg}`;
  navigator.clipboard.writeText(txt).then(()=>{
    alert('✓ Copiado para a área de transferência!\n\nAbra o WhatsApp Desktop/Web manualmente e cole.\n\n📞 +'+digits+'\n💬 '+msg.slice(0,80)+'...');
  }).catch(()=>{
    // Fallback: textarea trick
    const ta = document.createElement('textarea');
    ta.value = txt; document.body.appendChild(ta);
    ta.select(); document.execCommand('copy'); ta.remove();
    alert('✓ Copiado!\n\n📞 +'+digits+'\n\nCole no WhatsApp.');
  });
}

