// Export Excel — também respeita os filtros da tela
async function exportS4Excel(){
  if(!s4Rows.length) return;
  const filtered = await getFilteredS4Rows();
  if(!filtered.length) return alert('Nenhum registro com os filtros atuais.');
  const acts = await dbGetAll('actions');
  const out = filtered.map(r=>{
    const iss = checkIssues(r.saida,r.entrada,r.interj);
    const st = iss.length ? iss.map(i=>i.text).join(' | ') : 'OK';
    const myActs = acts.filter(a=>a.placa===r.placa && a.nome===r.nome)
      .map(a => a.acao + (a.data_infracao?' | Inf.'+a.data_infracao:'') + ' — ' + (a.data_acao||a.timestamp||''))
      .join(' | ');
    return {
      Placa:r.placa, Rota:r.rota, Tipo:r.stat, Nome:r.nome, Função:r.role,
      Saída:r.saida, Entrada:r.entrada, Interjornada:r.interj, Status:st, Ações:myActs
    };
  });
  const ws = XLSX.utils.json_to_sheet(out);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Controle');
  const fname = `Controle_Jornada_Export_${new Date().toISOString().slice(0,10)}.xlsx`;
  XLSX.writeFile(wb, fname);
}

