async function renderHistorico(){
  const acts=await dbGetAll('actions');
  const q=(document.getElementById('hist-search').value||'').toLowerCase();
  const af=document.getElementById('hist-filter-action').value;
  let filtered=acts.filter(a=>{
    if(q&&!((a.nome||'')+(a.placa||'')).toLowerCase().includes(q))return false;
    if(af!=='all'&&a.acao!==af)return false;
    return true;
  }).slice().reverse();
  const cont=document.getElementById('hist-list');
  if(!filtered.length){cont.innerHTML='<div style="font-size:13px;color:var(--text3);text-align:center;padding:40px">Nenhuma ação encontrada</div>';return;}
  const ACTION_COLORS={LIGAÇÃO:'blue','1ª ADVERTENCIA VERBAL':'warn','2ª ADVERTENCIA VERBAL':'warn','3ª ADVERTENCIA VERBAL':'warn','1ª ADVERTENCIA ESCRITA':'err','2ª ADVERTENCIA ESCRITA':'err','3ª ADVERTENCIA ESCRITA':'err','SUSPENSÃO':'err','A/C GERENCIA':'err',OK:'ok'};
  cont.innerHTML=filtered.map(a=>`<div class="hist-item">
    <div class="hist-dot" style="background:${a.acao.includes('SUSPENSÃO')||a.acao.includes('ESCRITA')?'var(--red)':a.acao.includes('VERBAL')?'var(--orange)':a.acao==='OK'?'var(--green)':'var(--blue)'}"></div>
    <div style="flex:1">
      <div class="hist-name">${esc(a.nome||'')} <span class="role-tag">${esc(a.role||'')} — ${esc(a.placa||'')}</span></div>
      <div class="hist-meta">${esc(a.data_acao||'')} ${esc(a.hora_acao||'')} ${a.data_infracao?'· Infração: '+esc(a.data_infracao):''}${a.observacao?'<br>'+esc(a.observacao):''}</div>
    </div>
    <div class="hist-action">
      <span class="badge badge-${ACTION_COLORS[a.acao]||'gray'}">${esc(a.acao)}</span>
      <button class="btn btn-ghost btn-sm" style="margin-top:5px" onclick="dbDelete('actions',${a.id}).then(()=>{renderHistorico();updateActionsBadge()})">✕</button>
    </div>
  </div>`).join('');
  updateActionsBadge();
}

async function updateActionsBadge(){
  const acts=await dbGetAll('actions');
  document.getElementById('nb-actions').textContent=acts.length;
  document.getElementById('d-acoes').textContent=acts.length;
}

function exportActionsJSON(){
  dbGetAll('actions').then(acts=>{
    const blob=new Blob([JSON.stringify({actions:acts,exported:new Date().toISOString()},null,2)],{type:'application/json'});
    dlBlob(blob,'marquespan_actions.json');
  });
}
async function importActionsJSON(){
  const inp=document.createElement('input');inp.type='file';inp.accept='application/json';inp.onchange=e=>{
    const f=e.target.files[0];if(!f)return;
    const reader=new FileReader();reader.onload=async ev=>{
      try{
        const obj=JSON.parse(ev.target.result);
        if(!obj.actions)return alert('JSON inválido.');
        if(!confirm(`Importar ${obj.actions.length} ações? Isso adicionará ao histórico existente.`))return;
        for(const a of obj.actions)await dbAdd('actions',{...a,id:undefined});
        renderHistorico();updateActionsBadge();alert('Importado com sucesso!');
      }catch(err){alert('Erro ao ler JSON.');}
    };reader.readAsText(f);
  };inp.click();
}
async function clearAllActions(){
  if(!confirm('Apagar TODO o histórico de ações? Esta ação não pode ser desfeita.'))return;
  await dbClear('actions');renderHistorico();updateActionsBadge();
}

