const cadData = {motoristas:{},auxiliares:{},veiculos:{},cidades:{}};
let cadEditKey = null, cadCurrentType = null;

// LocalStorage persistence for cadastros (fallback)
function cadLoad(){
  Object.keys(cadData).forEach(t=>{
    cadData[t]=lsGet('cad_'+t,{});
  });
}

// Async: carrega prioritariamente do IndexedDB, com fallback localStorage + seed
async function cadLoadAsync(){
  let usedDB = false;
  if(window.db && [...db.objectStoreNames].includes('cadastros')){
    for(const t of Object.keys(cadData)){
      const fromDB = await dbCadGet(t);
      if(fromDB && Object.keys(fromDB).length){
        cadData[t] = fromDB;
        usedDB = true;
      } else {
        // tenta localStorage
        const fromLS = lsGet('cad_'+t, {});
        cadData[t] = fromLS;
        // migra LS → DB se houver dados em LS
        if(Object.keys(fromLS).length){ await dbCadPut(t, fromLS); usedDB = true; }
      }
    }
  } else {
    cadLoad();
  }
  // Seed inicial (apenas se TUDO estiver vazio e seed estiver embutido)
  const seed = window.__CAD_SEED__;
  const totalCount = Object.values(cadData).reduce((a,o)=>a+Object.keys(o||{}).length,0);
  if(seed && totalCount===0 && !lsGet('cad_seeded_v1', false)){
    ['motoristas','auxiliares','veiculos','cidades'].forEach(t=>{
      if(seed[t]){
        cadData[t] = {...seed[t]};
        lsSet('cad_'+t, cadData[t]);
      }
    });
    // grava no IndexedDB também
    if(window.db && [...db.objectStoreNames].includes('cadastros')){
      for(const t of ['motoristas','auxiliares','veiculos','cidades']){
        await dbCadPut(t, cadData[t]);
      }
    }
    lsSet('cad_seeded_v1', true);
    console.log('[Cadastros] Seed inicial carregado:',
      Object.keys(cadData.motoristas).length,'motoristas,',
      Object.keys(cadData.auxiliares).length,'auxiliares,',
      Object.keys(cadData.veiculos).length,'veículos,',
      Object.keys(cadData.cidades).length,'cidades');
  }
  // Backfill: se cidades estiver vazio mas seed tem (seed v2)
  if(seed && seed.cidades && Object.keys(cadData.cidades||{}).length===0 && !lsGet('cad_seeded_cidades_v1', false)){
    cadData.cidades = {...seed.cidades};
    lsSet('cad_cidades', cadData.cidades);
    if(window.db && [...db.objectStoreNames].includes('cadastros')){
      await dbCadPut('cidades', cadData.cidades);
    }
    lsSet('cad_seeded_cidades_v1', true);
    console.log('[Cadastros] Backfill cidades:', Object.keys(cadData.cidades).length);
  }
  if(usedDB) updateDbStatusDetailed();

  // ☁ AUTO-PULL inicial: se local está vazio MAS nuvem tem dados, baixa.
  // Útil em novos dispositivos (login no celular pela 1ª vez, por exemplo).
  // Não bloqueia o boot — roda em background.
  setTimeout(() => cadAutoPullIfEmpty().catch(e => console.warn('[cadAutoPull]', e)), 1500);
}

// ☁ Pull "sempre" — baixa cadastros frescos da nuvem para TODOS os tipos
// e mescla com o estado local (nuvem sobrescreve). Diferente do
// cadAutoPullIfEmpty (que só baixa quando o tipo está vazio), este força
// um refresh — usado ao abrir a aba Cadastros para garantir que o usuário
// veja sempre o que outros operadores cadastraram.
async function cadPullAllFromCloud(){
  if(!supabaseAvailable()) return;
  if(typeof CLOUD_TABLES === 'undefined') return;
  const ind = document.getElementById('cad-sync-indicator');
  if(ind){
    ind.innerHTML = '☁ <span style="color:var(--blue)">Atualizando cadastros da nuvem...</span>';
    ind.style.background = 'var(--blue-l)';
    ind.style.opacity = '1';
  }
  let totalBaixado = 0;
  for(const type of Object.keys(CLOUD_TABLES)){
    const table = CLOUD_TABLES[type];
    try {
      const all = [];
      let from = 0, step = 1000;
      while(true){
        const resp = await sbFetch(`/rest/v1/${table}?select=*&order=${getPkCol(type)}.asc`, {
          method:'GET',
          headers:{'Range-Unit':'items','Range':`${from}-${from+step-1}`}
        });
        if(!resp.ok) break;
        const rows = await resp.json();
        all.push(...rows);
        if(rows.length < step) break;
        from += step;
      }
      if(!all.length) continue;
      const pkCol = getPkCol(type);
      const merged = {...(cadData[type] || {})};
      for(const row of all){
        const key = row[pkCol];
        if(!key) continue;
        const rec = {...row};
        delete rec.created_at; delete rec.updated_at; delete rec.updated_by;
        for(const k of Object.keys(rec)){ if(rec[k] === null) rec[k] = ''; }
        merged[key] = rec;
      }
      cadData[type] = merged;
      lsSet('cad_'+type, merged);
      try{ await dbCadPut(type, merged); }catch(e){}
      totalBaixado += all.length;
      try{ renderCadTable(type); }catch(e){}
    } catch(e){
      console.warn('[cadPullAllFromCloud]', type, e);
    }
  }
  refreshCadDbBanner();
  if(ind){
    const now = new Date().toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'});
    if(totalBaixado > 0){
      ind.innerHTML = `☁ <span style="color:var(--green)">${totalBaixado} registro(s) atualizado(s) da nuvem (${now})</span>`;
      ind.style.background = 'var(--green-l)';
    } else {
      ind.innerHTML = `✓ <span style="color:var(--text3)">Cadastros já atualizados (${now})</span>`;
      ind.style.background = 'var(--bg3)';
    }
    clearTimeout(window._cadSyncFadeTimer);
    window._cadSyncFadeTimer = setTimeout(() => { ind.style.opacity = '0.55'; }, 5000);
  }
}

// ☁ AUTO-PULL inicial: se local está vazio MAS nuvem tem dados, baixa.
async function cadAutoPullIfEmpty(){
  if(!supabaseAvailable()) return;
  if(typeof CLOUD_TABLES === 'undefined') return;
  // Conta registros locais por tipo
  const localCounts = {};
  for(const t of Object.keys(CLOUD_TABLES)){
    localCounts[t] = Object.keys(cadData[t] || {}).length;
  }
  // Identifica tipos com local vazio
  const tiposVazios = Object.entries(localCounts).filter(([_, n]) => n === 0).map(([t]) => t);
  if(!tiposVazios.length) return;   // tudo populado localmente, nada a fazer

  // Verifica se a nuvem tem dados nesses tipos
  const ind = document.getElementById('cad-sync-indicator');
  if(ind){
    ind.innerHTML = '☁ <span style="color:var(--blue)">Verificando dados na nuvem...</span>';
    ind.style.background = 'var(--blue-l)';
    ind.style.opacity = '1';
  }
  let totalBaixado = 0;
  for(const type of tiposVazios){
    const table = CLOUD_TABLES[type];
    try {
      const cloudN = await cloudCountRow(table);
      if(cloudN <= 0) continue;
      // Baixa SOMENTE para o tipo vazio
      const all = [];
      let from = 0, step = 1000;
      while(true){
        const resp = await sbFetch(`/rest/v1/${table}?select=*&order=${getPkCol(type)}.asc`, {
          method:'GET',
          headers:{'Range-Unit':'items', 'Range':`${from}-${from+step-1}`}
        });
        if(!resp.ok) break;
        const rows = await resp.json();
        all.push(...rows);
        if(rows.length < step) break;
        from += step;
      }
      const pkCol = getPkCol(type);
      const newMap = {};
      for(const row of all){
        const key = row[pkCol];
        if(!key) continue;
        const rec = {...row};
        delete rec.created_at; delete rec.updated_at; delete rec.updated_by;
        for(const k of Object.keys(rec)){ if(rec[k] === null) rec[k] = ''; }
        newMap[key] = rec;
      }
      cadData[type] = newMap;
      lsSet('cad_'+type, newMap);
      await dbCadPut(type, newMap);
      totalBaixado += all.length;
      // Re-renderiza esta aba
      try{ renderCadTable(type); }catch(e){}
    } catch(e){
      console.warn('[cadAutoPullIfEmpty]', type, e);
    }
  }
  if(totalBaixado > 0){
    refreshCadDbBanner();
    if(ind){
      const now = new Date().toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'});
      ind.innerHTML = `☁ <span style="color:var(--green)">Baixados ${totalBaixado} registros da nuvem (${now})</span>`;
      ind.style.background = 'var(--green-l)';
      clearTimeout(window._cadSyncFadeTimer);
      window._cadSyncFadeTimer = setTimeout(() => { ind.style.opacity = '0.55'; }, 5000);
    }
    console.log('[cadAutoPullIfEmpty]', totalBaixado, 'registros baixados da nuvem');
  } else if(ind){
    ind.innerHTML = '⚪ <span style="color:var(--text3)">Nuvem vazia ou sem dados novos</span>';
    ind.style.background = 'var(--bg3)';
    clearTimeout(window._cadSyncFadeTimer);
    window._cadSyncFadeTimer = setTimeout(() => { ind.style.opacity = '0.55'; }, 4000);
  }
}

// ═══════════════════════════════════════════════════════
//  💾 SALVAR CADASTRO — Local (sempre) + Nuvem (se disponível)
// ═══════════════════════════════════════════════════════
// Parâmetros:
//   type        — 'motoristas' | 'auxiliares' | 'veiculos' | 'cidades'
//   changedKey  — (opcional) chave do registro que mudou; se omitida, faz
//                 push do mapa inteiro. Use changedKey para edições pontuais
//                 (mais rápido). Use sem ele para imports em massa / clear.
//   isDelete    — (opcional) se true, é uma exclusão; DELETE no Supabase
//                 ao invés de UPSERT.
function cadSave(type, changedKey, isDelete){
  // 1) LOCAL — sempre, mesmo se nuvem falhar
  const ok = lsSet('cad_'+type, cadData[type]);
  // Grava também no IndexedDB
  dbCadPut(type, cadData[type]).then(saved => {
    if(saved) updateDbStatusDetailed();
    refreshCadDbBanner();
  }).catch(() => {});

  // 2) NUVEM — só se disponível, não-bloqueante, não-fatal
  if(supabaseAvailable() && CLOUD_TABLES[type]){
    // Async fire-and-forget; mostra feedback visual ao terminar
    cadSyncOne(type, changedKey, isDelete)
      .then(result => updateCadSyncIndicator(type, result))
      .catch(err => {
        console.warn('[cadSync]', type, err);
        updateCadSyncIndicator(type, {ok:false, error:err.message||String(err)});
      });
  }
  return ok;
}

// Faz upsert (ou delete) de UM registro específico OU do mapa inteiro
async function cadSyncOne(type, changedKey, isDelete){
  if(!supabaseAvailable()) return {ok:false, skipped:true};
  const table = CLOUD_TABLES[type];
  if(!table) throw new Error('Tipo desconhecido: '+type);

  // CASO 1: Exclusão pontual
  if(isDelete && changedKey){
    const pkCol = getPkCol(type);
    const pkVal = encodeURIComponent(changedKey);
    const resp = await sbFetch(`/rest/v1/${table}?${pkCol}=eq.${pkVal}`, {
      method:'DELETE',
      headers:{'Prefer':'return=minimal'}
    });
    if(!resp.ok) throw new Error(`DELETE ${table}: HTTP ${resp.status}`);
    return {ok:true, deleted:1};
  }

  // CASO 2: Upsert pontual (1 registro)
  if(changedKey && cadData[type][changedKey]){
    const row = _toRow(type, changedKey, cadData[type][changedKey]);
    const resp = await sbFetch(`/rest/v1/${table}?on_conflict=${getPkCol(type)}`, {
      method:'POST',
      headers:{'Prefer':'resolution=merge-duplicates,return=minimal'},
      body: JSON.stringify([row])
    });
    if(!resp.ok){
      const txt = await resp.text().catch(()=>'');
      throw new Error(`UPSERT ${table}: HTTP ${resp.status} — ${txt.slice(0,150)}`);
    }
    return {ok:true, upserted:1};
  }

  // CASO 3: Push do mapa inteiro (import em lote, clear, etc.)
  const records = Object.entries(cadData[type] || {});
  if(!records.length){
    // Map vazio = limpar tudo. (Por segurança, NÃO fazemos DELETE em massa aqui —
    // o usuário deve usar "Limpar nuvem" explícito no modal.)
    return {ok:true, upserted:0, note:'mapa vazio — nenhuma ação na nuvem'};
  }
  let upserted = 0;
  const BATCH = 500;
  for(let i=0; i<records.length; i+=BATCH){
    const slice = records.slice(i, i+BATCH).map(([k,v]) => _toRow(type, k, v));
    const resp = await sbFetch(`/rest/v1/${table}?on_conflict=${getPkCol(type)}`, {
      method:'POST',
      headers:{'Prefer':'resolution=merge-duplicates,return=minimal'},
      body: JSON.stringify(slice)
    });
    if(!resp.ok){
      const txt = await resp.text().catch(()=>'');
      throw new Error(`Lote ${i+1}-${i+slice.length}: HTTP ${resp.status} — ${txt.slice(0,120)}`);
    }
    upserted += slice.length;
  }
  return {ok:true, upserted};
}

// Pequeno indicador visual de status da última sincronização
function updateCadSyncIndicator(type, result){
  const el = document.getElementById('cad-sync-indicator');
  if(!el) return;
  const now = new Date().toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'});
  if(result?.ok){
    if(result.skipped){
      el.innerHTML = '⚪ <span style="color:var(--text3)">Nuvem indisponível — só local</span>';
      el.style.background = 'var(--bg3)';
    } else if(result.deleted){
      el.innerHTML = `☁ <span style="color:var(--blue)">Excluído da nuvem (${now})</span>`;
      el.style.background = 'var(--blue-l)';
    } else {
      el.innerHTML = `☁ <span style="color:var(--green)">Sincronizado: ${result.upserted} registro(s) (${now})</span>`;
      el.style.background = 'var(--green-l)';
    }
  } else {
    el.innerHTML = `⚠ <span style="color:var(--red)" title="${esc(result?.error||'')}">Falha na nuvem — salvo só local</span>`;
    el.style.background = 'var(--red-l)';
  }
  el.style.opacity = '1';
  // Fade após 4s
  clearTimeout(window._cadSyncFadeTimer);
  window._cadSyncFadeTimer = setTimeout(() => { el.style.opacity = '0.55'; }, 4000);
}

// IndexedDB for cadastros (also save there if available)
function cadLoadAll(){
  cadLoadAsync().then(()=>{
    Object.keys(cadData).forEach(t=>renderCadTable(t));
    refreshCadDbBanner();
  });
}

function refreshCadDbBanner(){
  const el = document.getElementById('cad-db-summary');
  if(!el) return;
  const m=Object.keys(cadData.motoristas||{}).length;
  const a=Object.keys(cadData.auxiliares||{}).length;
  const v=Object.keys(cadData.veiculos||{}).length;
  const c=Object.keys(cadData.cidades||{}).length;
  const total=m+a+v+c;
  const sourceLabel = window.db ? 'IndexedDB' : 'localStorage (fallback)';
  el.innerHTML = `<strong style="color:var(--text2)">${total}</strong> registros · `+
    `${m} motoristas, ${a} auxiliares, ${v} veículos, ${c} cidades · `+
    `<span style="color:var(--text3)">salvo em ${sourceLabel}</span>`;
}

async function exportCadastrosBackup(){
  // Sempre lê o estado atual de cadData (já hidrata IDB no boot)
  const payload = {
    version: 1,
    exported_at: new Date().toISOString(),
    motoristas: cadData.motoristas || {},
    auxiliares: cadData.auxiliares || {},
    veiculos:   cadData.veiculos   || {},
    cidades:    cadData.cidades    || {}
  };
  const json = JSON.stringify(payload, null, 2);
  const blob = new Blob([json], {type:'application/json'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `cadastros-backup-${new Date().toISOString().slice(0,10)}.json`;
  a.click();
  URL.revokeObjectURL(a.href);
  const total = Object.keys(payload.motoristas).length + Object.keys(payload.auxiliares).length +
                Object.keys(payload.veiculos).length + Object.keys(payload.cidades).length;
  console.log('[Backup] Exportado:', total, 'registros');
}

function importCadastrosBackup(){
  const inp = document.createElement('input');
  inp.type='file'; inp.accept='.json,application/json';
  inp.onchange = async e=>{
    const f = e.target.files[0]; if(!f) return;
    let payload;
    try{ payload = JSON.parse(await f.text()); }
    catch(err){ alert('Arquivo inválido — não é um JSON válido.'); return; }
    if(!payload || typeof payload!=='object' || (!payload.motoristas && !payload.auxiliares && !payload.veiculos && !payload.cidades)){
      alert('Arquivo não parece um backup de cadastros.'); return;
    }
    const mode = confirm(
      'Modo de importação:\n\n'+
      '• OK = SUBSTITUIR todos os cadastros atuais\n'+
      '• Cancelar = MESCLAR (adicionar/atualizar sem apagar existentes)'
    );
    for(const t of ['motoristas','auxiliares','veiculos','cidades']){
      const incoming = payload[t] || {};
      if(mode){
        cadData[t] = {...incoming};
      } else {
        cadData[t] = {...(cadData[t]||{}), ...incoming};
      }
      lsSet('cad_'+t, cadData[t]);
      await dbCadPut(t, cadData[t]);
    }
    Object.keys(cadData).forEach(t=>renderCadTable(t));
    refreshCadDbBanner();
    updateDbStatusDetailed();
    const total = Object.keys(cadData.motoristas).length + Object.keys(cadData.auxiliares).length +
                  Object.keys(cadData.veiculos).length + Object.keys(cadData.cidades).length;
    alert(`✓ Backup restaurado (${mode?'substituído':'mesclado'}). Total agora: ${total} registros.`);
  };
  inp.click();
}

// ═══════════════════════════════════════════════════════════════════
//  CLOUD SYNC — Supabase REST
// ═══════════════════════════════════════════════════════════════════
const CLOUD_TABLES = {
  motoristas: 'cadastros_motoristas',
  auxiliares: 'cadastros_auxiliares',
  veiculos:   'cadastros_veiculos',
  cidades:    'cadastros_cidades'
};

function openCloudSyncModal(){
  document.getElementById('cloud-sync-overlay').classList.add('open');
  cloudTestConnection();
}
function closeCloudSyncModal(){
  document.getElementById('cloud-sync-overlay').classList.remove('open');
}
function cloudStatus(msg, kind='info'){
  const el = document.getElementById('cloud-status');
  if(!el) return;
  const colors = {
    info:    {bg:'var(--bg3)',     bd:'var(--border)',   fg:'var(--text2)'},
    success: {bg:'var(--green-l)', bd:'var(--green-b)',  fg:'var(--green)'},
    warn:    {bg:'var(--orange-l)',bd:'var(--orange-b)', fg:'var(--orange)'},
    error:   {bg:'var(--red-l)',   bd:'var(--red-b)',    fg:'var(--red)'},
    working: {bg:'var(--blue-l)',  bd:'var(--blue-b)',   fg:'var(--blue)'}
  };
  const c = colors[kind] || colors.info;
  el.style.background = c.bg;
  el.style.borderColor = c.bd;
  el.style.color = c.fg;
  el.innerHTML = msg;
}

async function cloudCountRow(table){
  // HEAD request com Prefer: count=exact retorna Content-Range com total
  const resp = await sbFetch(`/rest/v1/${table}?select=*&limit=1`, {
    method:'GET',
    headers:{ 'Prefer':'count=exact', 'Range-Unit':'items', 'Range':'0-0' }
  });
  if(!resp.ok) throw new Error(`${table}: HTTP ${resp.status}`);
  const cr = resp.headers.get('content-range') || '';
  // Formato "0-0/123"  ou  "*/0"
  const m = cr.match(/\/(\d+)$/);
  return m ? parseInt(m[1]) : 0;
}

async function cloudTestConnection(){
  cloudStatus('🔄 Verificando conexão e tabelas...', 'working');
  const tbody = document.getElementById('cloud-table-body');
  const wrap  = document.getElementById('cloud-table-status');
  tbody.innerHTML = ''; wrap.style.display = 'block';
  let allOk = true, anyMissing = false;
  const results = [];
  for(const [type, table] of Object.entries(CLOUD_TABLES)){
    const localCount = Object.keys(cadData[type]||{}).length;
    let cloudCount = null, state='', stateColor='';
    try{
      cloudCount = await cloudCountRow(table);
      if(cloudCount === localCount){ state='✓ sincronizado'; stateColor='var(--green)'; }
      else if(cloudCount === 0){ state='⚠ vazio'; stateColor='var(--orange)'; }
      else if(cloudCount < localCount){ state='⬆ local maior'; stateColor='var(--orange)'; }
      else { state='⬇ nuvem maior'; stateColor='var(--blue)'; }
    }catch(e){
      const msg = String(e.message||'');
      if(/not.found|404|relation.*does not exist|not.exist/i.test(msg)){
        state='✕ tabela ausente'; stateColor='var(--red)'; anyMissing=true; allOk=false;
      } else if(/401|jwt|unauthorized/i.test(msg)){
        state='✕ não autenticado'; stateColor='var(--red)'; allOk=false;
      } else {
        state='✕ erro'; stateColor='var(--red)'; allOk=false;
      }
    }
    results.push({type, table, localCount, cloudCount, state, stateColor});
  }
  tbody.innerHTML = results.map(r=>`
    <tr>
      <td style="padding:7px 12px;border-top:1px solid var(--border);font-family:monospace;font-size:11px">${r.table}</td>
      <td style="padding:7px 12px;border-top:1px solid var(--border);text-align:right;font-family:monospace">${r.localCount}</td>
      <td style="padding:7px 12px;border-top:1px solid var(--border);text-align:right;font-family:monospace">${r.cloudCount===null?'—':r.cloudCount}</td>
      <td style="padding:7px 12px;border-top:1px solid var(--border);text-align:center;font-weight:600;color:${r.stateColor}">${r.state}</td>
    </tr>
  `).join('');

  if(anyMissing){
    cloudStatus(
      '⚠ <strong>Tabelas faltando no Supabase.</strong> Abra o arquivo <code>supabase-schema.sql</code> e cole no SQL Editor do Supabase.',
      'warn'
    );
  } else if(allOk){
    const totalLocal = results.reduce((a,r)=>a+r.localCount,0);
    const totalCloud = results.reduce((a,r)=>a+(r.cloudCount||0),0);
    cloudStatus(
      `✓ Conectado · <strong>${totalLocal}</strong> registros locais · <strong>${totalCloud}</strong> registros na nuvem`,
      totalLocal===totalCloud ? 'success' : 'info'
    );
  } else {
    cloudStatus('✕ Erro de conexão. Veja Console (F12) para detalhes.', 'error');
  }
}

function cleanText(v){
  if(v === undefined || v === null) return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}
function cleanBool(v, def=true){
  if(v === undefined || v === null || v === '') return def;
  if(typeof v === 'boolean') return v;
  const s = String(v).trim().toUpperCase();
  if(['N','NAO','NÃO','FALSE','0','INATIVO','DESLIGADO'].includes(s)) return false;
  if(['S','SIM','TRUE','1','ATIVO'].includes(s)) return true;
  return def;
}
function _toRow(type, key, rec){
  // Retorna sempre o MESMO conjunto de chaves por tabela.
  // Isso evita o erro Supabase/PostgREST PGRST102: "All object keys must match".
  const r = rec || {};
  if(type === 'motoristas'){
    return {
      nome_escala: cleanText(r.nome_escala || key)?.toUpperCase() || String(key||'').trim().toUpperCase(),
      nome_ponto: cleanText(r.nome_ponto || r.nome_completo || r.nome || null),
      funcao: cleanText(r.funcao || 'MOTORISTA'),
      telefone: cleanText(r.telefone || r.tel || r.tel_pessoal || null),
      tel_corp: cleanText(r.tel_corp || r.telefone_corporativo || null),
      cpf: cleanText(r.cpf || null),
      obs: cleanText(r.obs || r.observacao || null),
      admissao: cleanText(r.admissao || null),
      ativo: cleanBool(r.ativo, true),
      data_desligamento: cleanText(r.data_desligamento || null)
    };
  }
  if(type === 'auxiliares'){
    return {
      nome_escala: cleanText(r.nome_escala || key)?.toUpperCase() || String(key||'').trim().toUpperCase(),
      nome_ponto: cleanText(r.nome_ponto || r.nome_completo || r.nome || null),
      funcao: cleanText(r.funcao || 'AUXILIAR'),
      telefone: cleanText(r.telefone || r.tel || r.tel_pessoal || null),
      tel_corp: cleanText(r.tel_corp || r.telefone_corporativo || null),
      cpf: cleanText(r.cpf || null),
      obs: cleanText(r.obs || r.observacao || null),
      admissao: cleanText(r.admissao || null),
      ativo: cleanBool(r.ativo, true),
      data_desligamento: cleanText(r.data_desligamento || null)
    };
  }
  if(type === 'veiculos'){
    return {
      placa: cleanText(r.placa || key)?.toUpperCase() || String(key||'').trim().toUpperCase(),
      marca: cleanText(r.marca || null),
      modelo: cleanText(r.modelo || null),
      tipo: cleanText(r.tipo || null),
      filial: cleanText(r.filial || null),
      capacidade: cleanText(r.capacidade || null),
      rota_padrao: cleanText(r.rota_padrao || r.rota || null),
      obs: cleanText(r.obs || r.observacao || null),
      ativo: cleanBool(r.ativo, true)
    };
  }
  if(type === 'cidades'){
    return {
      rota: cleanText(r.rota || key) || String(key||'').trim(),
      cidade: cleanText(r.cidade || r.nome || null),
      uf: cleanText(r.uf || r.estado || null),
      obs: cleanText(r.obs || r.observacao || null),
      ativo: cleanBool(r.ativo, true)
    };
  }
  throw new Error('Tipo desconhecido: '+type);
}

async function cloudPushAll(){
  if(!confirm(`Enviar todos os cadastros locais para a nuvem?\n\nIsto faz UPSERT (insere novos + atualiza existentes), mas NÃO apaga registros que existem na nuvem mas não localmente.`)) return;
  const btn = document.getElementById('cloud-push-btn');
  btn.disabled = true; btn.style.opacity='.6';
  let totalPushed = 0, errors = [];
  for(const [type, table] of Object.entries(CLOUD_TABLES)){
    const records = Object.entries(cadData[type]||{});
    if(!records.length) continue;
    cloudStatus(`⬆ Enviando <strong>${records.length}</strong> registros para <code>${table}</code>...`, 'working');
    // Envia em lotes de 500 (limite seguro do Supabase)
    const BATCH = 500;
    for(let i=0;i<records.length;i+=BATCH){
      const slice = records.slice(i, i+BATCH).map(([k,v])=>_toRow(type, k, v));
      try{
        const resp = await sbFetch(`/rest/v1/${table}?on_conflict=${getPkCol(type)}`, {
          method:'POST',
          headers:{
            'Content-Type':'application/json',
            'Prefer':'resolution=merge-duplicates,return=minimal'
          },
          body: JSON.stringify(slice)
        });
        if(!resp.ok){
          const txt = await resp.text();
          errors.push(`${table} [${i}-${i+slice.length}]: HTTP ${resp.status} ${txt.slice(0,120)}`);
          break;
        }
        totalPushed += slice.length;
      }catch(e){
        errors.push(`${table}: ${e.message}`);
        break;
      }
    }
  }
  btn.disabled = false; btn.style.opacity='1';
  if(errors.length){
    cloudStatus(
      `⚠ Enviados ${totalPushed} registros, mas com erros:<br><span style="font-family:monospace;font-size:10.5px">${errors.join('<br>')}</span>`,
      'error'
    );
    console.error('[cloudPush] erros:', errors);
  } else {
    cloudStatus(`✓ <strong>${totalPushed}</strong> registros enviados com sucesso para a nuvem!`, 'success');
  }
  // Refresh contagens
  setTimeout(cloudTestConnection, 800);
}

async function cloudPullAll(){
  if(!confirm(`Baixar todos os cadastros da nuvem?\n\nIsto SUBSTITUI seus cadastros locais pelos dados da nuvem.`)) return;
  const btn = document.getElementById('cloud-pull-btn');
  btn.disabled = true; btn.style.opacity='.6';
  let totalPulled = 0, errors = [];
  for(const [type, table] of Object.entries(CLOUD_TABLES)){
    cloudStatus(`⬇ Baixando <code>${table}</code>...`, 'working');
    try{
      // Paginação: Supabase retorna no máx 1000 por padrão. Pega tudo via range.
      const all = [];
      let from=0, step=1000;
      while(true){
        const resp = await sbFetch(`/rest/v1/${table}?select=*&order=${getPkCol(type)}.asc`, {
          method:'GET',
          headers:{ 'Range-Unit':'items', 'Range':`${from}-${from+step-1}` }
        });
        if(!resp.ok){ errors.push(`${table}: HTTP ${resp.status}`); break; }
        const rows = await resp.json();
        all.push(...rows);
        if(rows.length < step) break;
        from += step;
      }
      // Constrói o map por PK
      const pkCol = getPkCol(type);
      const newMap = {};
      for(const row of all){
        const key = row[pkCol];
        if(!key) continue;
        // Limpa campos só da nuvem
        const rec = {...row};
        delete rec.created_at; delete rec.updated_at; delete rec.updated_by;
        // Converte null → ''
        for(const k of Object.keys(rec)){ if(rec[k]===null) rec[k]=''; }
        newMap[key] = rec;
      }
      cadData[type] = newMap;
      lsSet('cad_'+type, newMap);
      await dbCadPut(type, newMap);
      totalPulled += all.length;
    }catch(e){
      errors.push(`${type}: ${e.message}`);
    }
  }
  // Re-render
  Object.keys(cadData).forEach(t=>renderCadTable(t));
  refreshCadDbBanner();
  updateDbStatusDetailed();
  btn.disabled = false; btn.style.opacity='1';
  if(errors.length){
    cloudStatus(`⚠ Baixados ${totalPulled} registros com erros: ${errors.join(' · ')}`, 'error');
  } else {
    cloudStatus(`✓ <strong>${totalPulled}</strong> registros baixados e salvos localmente!`, 'success');
  }
  setTimeout(cloudTestConnection, 800);
}

function getPkCol(type){
  return {motoristas:'nome_escala', auxiliares:'nome_escala', veiculos:'placa', cidades:'rota'}[type];
}

function abrirSchemaSQL(){
  // Tenta abrir o schema de cadastros (criado nesta versão). Fallback para o antigo.
  // Os dois arquivos vivem ao lado do HTML quando publicado.
  const candidatos = ['supabase-schema-cadastros.sql', 'supabase-schema.sql'];
  // Tenta cada um em ordem; o primeiro que existir vai abrir
  (async () => {
    for(const url of candidatos){
      try{
        const r = await fetch(url, {method:'HEAD'});
        if(r.ok){ window.open(url, '_blank'); return; }
      }catch(e){}
    }
    // Nenhum acessível — mostra instruções
    alert('Arquivo SQL não encontrado ao lado do HTML.\n\nPeça o schema SQL ao desenvolvedor ou baixe novamente o arquivo "supabase-schema-cadastros.sql".\n\nVocê pode também colar este conteúdo direto no SQL Editor do Supabase.');
  })();
}

