// Import names from ponto file to pre-populate cadastro
// User picks a ponto XLSX, we extract all unique names and add them
// as skeleton records (nome_ponto filled, nome_escala empty — user fills later)
async function importNomesFromPonto(type){
  const inp=document.createElement('input');inp.type='file';inp.accept='.xlsx,.xls';
  inp.onchange=async e=>{
    const f=e.target.files[0];if(!f)return;
    const buf=await f.arrayBuffer();
    const wb=XLSX.read(buf,{type:'array',raw:false});
    const ws=wb.Sheets[wb.SheetNames[0]];
    const raw=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});
    
    // Find header row
    let hdrRow=-1;
    for(let i=0;i<Math.min(raw.length,15);i++){
      const u=raw[i].map(v=>norm(v));
      if(u.includes('DATA')&&u.includes('NOME')){hdrRow=i;break;}
    }
    if(hdrRow<0){alert('Cabeçalho não encontrado no arquivo.');return;}
    
    const hdrs=raw[hdrRow].map(v=>norm(v));
    const iNOME=hdrs.indexOf('NOME');
    if(iNOME<0){alert('Coluna NOME não encontrada.');return;}
    
    // Extract unique names (cleaned)
    const names=new Set();
    for(let i=hdrRow+1;i<raw.length;i++){
      let nome=norm(raw[i][iNOME]||'');
      if(!nome||nome.startsWith('LOG NOT')||nome==='TOTAL')continue;
      nome=nome.replace(/^LOG\s*T?\s*-\s*/,'').replace(/\s+/g,' ').trim();
      if(nome)names.add(nome);
    }
    
    // Add as skeleton records (if not already in cadastro)
    let added=0;
    for(const nome of names){
      if(!cadData[type][nome]){
        cadData[type][nome]={
          nome_escala:'',        // user must fill: name as it appears in escala
          nome_ponto:nome,       // auto-filled from ponto
          funcao:type==='motoristas'?'MOTORISTA':'AUXILIAR',
          telefone:'',
          cpf:'',
          obs:'Importado do ponto — preencher nome da escala'
        };
        added++;
      }
    }
    cadSave(type);
    renderCadTable(type);
    alert(
      added>0
        ? added+' nomes importados do ponto!\n\nAgora preencha o campo "Nome na Escala" para cada um (como aparece no Roteiro SP).'
        : 'Nenhum nome novo — todos já cadastrados.'
    );
  };
  inp.click();
}

function setCadTab(tab, el){
  document.querySelectorAll('.cad-tab').forEach(t=>t.classList.remove('active'));
  el.classList.add('active');
  document.querySelectorAll('.cad-panel').forEach(p=>p.style.display='none');
  document.getElementById('cad-tab-'+tab).style.display='';
  cadCurrentType = tab;
  renderCadTable(tab);
}

function renderCadTable(type){
  const schema = CAD_SCHEMAS[type];
  const wrap = document.getElementById('cad-table-'+type);
  if(!wrap) return;
  const q = (document.getElementById('srch-'+type)?.value||'').toLowerCase();
  // 🔒 Filtro "Mostrar inativos" (default: ocultos)
  const showInactive = document.getElementById('show-inactive-'+type)?.checked || false;
  const isPersonnel = type==='motoristas'||type==='auxiliares';
  const rows = Object.values(cadData[type]||{}).filter(r=>{
    // Oculta inativos por padrão (apenas para motoristas/auxiliares)
    if(isPersonnel && !showInactive && r.ativo===false) return false;
    if(!q) return true;
    return schema.searchKeys.some(k=>String(r[k]||'').toLowerCase().includes(q));
  }).sort((a,b)=>{
    // Ativos vêm primeiro
    if(isPersonnel){
      const aIn = a.ativo===false ? 1 : 0;
      const bIn = b.ativo===false ? 1 : 0;
      if(aIn!==bIn) return aIn-bIn;
    }
    const ka=String(a[schema.pkKey]||''), kb=String(b[schema.pkKey]||'');
    const na=parseInt(ka), nb=parseInt(kb);
    return !isNaN(na)&&!isNaN(nb)?na-nb:ka.localeCompare(kb);
  });
  // Atualiza o contador (mostra ativos x total p/ funcionários)
  const cnt = document.getElementById('cnt-'+type);
  if(cnt){
    if(isPersonnel){
      const all = Object.values(cadData[type]||{});
      const ativos = all.filter(r=>r.ativo!==false).length;
      const inativos = all.length - ativos;
      cnt.innerHTML = `${ativos} ativo(s)${inativos?` · <span style="color:var(--text3)">${inativos} inativo(s)</span>`:''}`;
    } else {
      cnt.textContent = `${Object.keys(cadData[type]).length} registro(s)`;
    }
  }
  if(!rows.length){
    wrap.innerHTML=`<div style="padding:24px;text-align:center;color:var(--text3);font-size:13px">Nenhum registro${q?' com este filtro':' cadastrado'}. Clique em "+ Novo" para adicionar.</div>`;
    return;
  }
  const hasStatus = isPersonnel;
  const statusCol = hasStatus ? '<th style="width:44px;text-align:center">✓</th>' : '';
  const ths = statusCol+schema.cols.map(c=>`<th>${c}</th>`).join('')+'<th style="width:160px"></th>';
  const trs = rows.map(r=>{
    const pk = r[schema.pkKey];
    const isInactive = isPersonnel && r.ativo===false;
    // Link status for motoristas/auxiliares
    const isLinked = isPersonnel && r.nome_escala && r.nome_ponto;
    const hasTel = isPersonnel && r.telefone;
    // Status icon only for personnel
    const statusIcon = isPersonnel
      ? (isInactive
          ? `<span title="Funcionário INATIVO — não aparece em escalas novas, mas histórico está preservado" style="color:var(--text3);font-size:14px;cursor:help">⊘</span>`
          : (isLinked
              ? `<span title="Vinculado: ${esc(r.nome_escala)} → ${esc(r.nome_ponto)}" style="color:var(--green);font-size:14px;cursor:help">✓</span>`
              : `<span title="Preencher nome da escala" style="color:var(--orange);font-size:14px;cursor:help">⚠</span>`))
      : '';
    const telIcon = hasTel && !isInactive
      ? `<span title="WA: ${esc(r.telefone)}" style="color:#25D366;font-size:12px;cursor:help"> 📱</span>`
      : '';
    const tds = schema.keys.map(k=>{
      const v = String(r[k]||'');
      if(k==='nome_escala'&&!v&&isPersonnel)
        return`<td><span style="color:var(--orange);font-style:italic;font-size:11px">⚠ Preencher</span></td>`;
      if(k==='telefone'&&v)
        return`<td style="font-family:monospace;font-size:12px">${esc(v)}</td>`;
      return`<td>${esc(v||'—')}</td>`;
    }).join('');
    const rowStyle = isInactive
      ? 'background:rgba(120,120,120,.06);opacity:.55;font-style:italic'
      : (!isLinked && isPersonnel ? 'background:rgba(217,119,6,.04)' : '');
    // Botão Inativar/Ativar — apenas para motoristas/auxiliares
    const toggleBtn = isPersonnel
      ? (isInactive
          ? `<button onclick="toggleCadAtivo('${type}','${esc(String(pk))}',true)" title="Reativar funcionário" style="padding:3px 8px;border-radius:5px;border:1px solid var(--green-b);background:var(--green-l);color:var(--green);font-size:11px;cursor:pointer;font-family:inherit;font-weight:600">↻ Reativar</button>`
          : `<button onclick="toggleCadAtivo('${type}','${esc(String(pk))}',false)" title="Inativar (desligamento) — preserva todo o histórico" style="padding:3px 8px;border-radius:5px;border:1px solid #d4a000;background:#fffbe6;color:#8a6500;font-size:11px;cursor:pointer;font-family:inherit;font-weight:600">⊘ Inativar</button>`)
      : '';
    return`<tr style="${rowStyle}">
      ${isPersonnel?`<td style="padding:6px 8px;text-align:center">${statusIcon}${telIcon}</td>`:''}
      ${tds}
      <td>
        <div style="display:flex;gap:4px;flex-wrap:wrap">
          <button onclick="openCadModal('${type}','${esc(String(pk))}')" title="Editar" style="padding:3px 8px;border-radius:5px;border:1px solid var(--border);background:var(--bg3);color:var(--text2);font-size:11px;cursor:pointer;font-family:inherit">✎</button>
          ${hasTel&&!isInactive?`<button onclick="openWhatsApp('${esc(r.nome_ponto||r.nome_escala||pk)}','${esc(r.telefone)}',null)" title="WhatsApp" style="padding:3px 8px;border-radius:5px;border:none;background:#25D366;color:#fff;font-size:11px;cursor:pointer">WA</button>`:''}
          ${toggleBtn}
          <button onclick="deleteCadRecord('${type}','${esc(String(pk))}')" title="Excluir permanentemente (perde histórico!)" style="padding:3px 8px;border-radius:5px;border:1px solid var(--red-b);background:var(--red-l);color:var(--red);font-size:11px;cursor:pointer;font-family:inherit">✕</button>
        </div>
      </td>
    </tr>`;
  }).join('');
  wrap.innerHTML=`<table class="cad-table"><thead><tr>${ths}</tr></thead><tbody>${trs}</tbody></table>`;
}

// 🔒 Inativar / Reativar funcionário — preserva todo o histórico
function toggleCadAtivo(type, pk, ativar){
  const rec = cadData[type] && cadData[type][pk];
  if(!rec) return;
  if(ativar){
    if(!confirm(`Reativar "${pk}"?\nVoltará a aparecer em escalas novas.`)) return;
    rec.ativo = true;
    delete rec.data_desligamento;
  } else {
    if(!confirm(`Inativar "${pk}" por desligamento?\n\n✓ O histórico de ações e relatórios continuam preservados.\n✗ Não aparecerá mais em escalas novas.\n\nUse "Excluir" (✕) apenas se for cadastro errado/duplicado.`)) return;
    rec.ativo = false;
    rec.data_desligamento = new Date().toISOString().slice(0,10);
  }
  cadSave(type, pk);   // 🔗 sync no Supabase: estado ativo/inativo
  renderCadTable(type);
  if(s4Rows.length) buildACData();
}

function openCadModal(type, pk=null){
  cadCurrentType = type;
  cadEditKey = pk;
  const schema = CAD_SCHEMAS[type];
  document.getElementById('cad-modal-title').textContent = pk ? `Editar ${schema.title.slice(0,-1)}` : `Novo(a) ${schema.title.slice(0,-1)}`;
  const rec = pk ? (cadData[type][pk]||{}) : {};
  const fieldsHtml = schema.keys.map((k,i)=>{
    const label = schema.cols[i];
    const val = esc(String(rec[k]||''));
    const isRequired = k===schema.pkKey;
    return`<div class="form-group" style="margin-bottom:0">
      <label class="form-label">${label}${isRequired?' <span style="color:var(--red)">*</span>':''}</label>
      <input class="form-control" id="cad-field-${k}" value="${val}" placeholder="${label}" ${pk&&k===schema.pkKey?'readonly style="background:var(--bg3);color:var(--text3)"':''}>
    </div>`;
  }).join('');
  document.getElementById('cad-modal-fields').innerHTML = fieldsHtml;
  document.getElementById('cad-modal-overlay').classList.add('open');
  // Focus first editable field
  const first = document.querySelector('#cad-modal-fields input:not([readonly])');
  if(first) setTimeout(()=>first.focus(),100);
}

function closeCadModal(){
  document.getElementById('cad-modal-overlay').classList.remove('open');
  cadEditKey = null;
}

function saveCadRecord(){
  const type = cadCurrentType;
  const schema = CAD_SCHEMAS[type];
  const rec = {};
  for(const k of schema.keys){
    const el = document.getElementById('cad-field-'+k);
    rec[k] = el ? el.value.trim() : '';
  }
  const pk = rec[schema.pkKey];
  if(!pk){ alert('O campo "'+schema.cols[schema.keys.indexOf(schema.pkKey)]+'" é obrigatório.'); return; }
  // Auto-set funcao
  if((type==='motoristas'||type==='auxiliares')&&!rec.funcao){
    rec.funcao=type==='motoristas'?'MOTORISTA':'AUXILIAR';
  }
  cadData[type][pk] = rec;
  cadSave(type, pk);   // 🔗 sync no Supabase: só o registro alterado
  // Auto-save phone to phones DB when telefone filled
  if(rec.telefone&&(type==='motoristas'||type==='auxiliares')){
    const pNome=rec.nome_ponto||rec.nome_escala||pk;
    dbSavePhone(pNome,rec.telefone,rec.funcao).catch(()=>{});
    if(rec.nome_escala&&rec.nome_escala!==pNome)
      dbSavePhone(rec.nome_escala,rec.telefone,rec.funcao).catch(()=>{});
  }
  closeCadModal();
  renderCadTable(type);
  if(s4Rows.length) buildACData();
}

function deleteCadRecord(type, pk){
  const isPersonnel = (type==='motoristas'||type==='auxiliares');
  let msg = 'Remover este registro permanentemente?';
  if(isPersonnel){
    msg = `⚠ ATENÇÃO\n\nExcluir permanentemente "${pk}"?\n\nSe é um desligamento, use o botão "⊘ Inativar" — ele preserva todo o histórico (ações, relatórios, semanas salvas).\n\nExcluir é IRREVERSÍVEL e remove o cadastro do banco (o histórico de ações em si fica, mas você perde o contato/CPF/telefone).\n\nContinuar com a exclusão?`;
  }
  if(!confirm(msg)) return;
  delete cadData[type][pk];
  cadSave(type, pk, true);   // 🔗 sync no Supabase: DELETE
  renderCadTable(type);
}

async function importFromXLSX(type){
  const inp=document.createElement('input');
  inp.type='file';inp.accept='.xlsx,.xls';
  inp.onchange=async e=>{
    const f=e.target.files[0];if(!f)return;
    const buf=await f.arrayBuffer();
    const wb=XLSX.read(buf,{type:'array',raw:false,cellDates:false});

    // Clean phone to digits only
    const cleanPhone=v=>{
      if(!v||v==='-')return'';
      const s=String(v).split(/[,\/]/)[0].trim();
      const d=s.replace(/[^0-9]/g,'');
      return d.length>=8?d:'';
    };

    // Save phone under multiple name variants
    const savePh=async(esc,cmp,tel,obs)=>{
      if(!tel)return;
      if(cmp)await dbSavePhone(cmp,tel,obs).catch(()=>{});
      if(esc&&esc!==cmp)await dbSavePhone(esc,tel,obs).catch(()=>{});
    };

    const shUpper=wb.SheetNames.map(s=>s.trim().toUpperCase());
    // Normalize accents for sheet name detection
    const normAcc=s=>s.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toUpperCase();
    const shNorm=wb.SheetNames.map(s=>normAcc(s.trim()));
    const isQuadro=shNorm.some(s=>s.includes('FUNCIONARI')||s.includes('FUNCIONARIOS'));
    const isRoteiro=wb.SheetNames.some(s=>['SEGUNDA','TERCA','QUARTA'].includes(s.trim().toUpperCase())||s.trim().toUpperCase()==='SEGUNDA');
    let imported=0;

    // ── FORMATO A: Quadro de Funcionários ─────────────────────
    if(isQuadro){
      const sn=wb.SheetNames.find(s=>normAcc(s.trim()).includes('FUNCIONARI'))||wb.SheetNames[0];
      const raw=XLSX.utils.sheet_to_json(wb.Sheets[sn],{header:1,defval:'',raw:false});
      const hdrs=raw[0].map(v=>normAcc(String(v||'').trim()));
      const ci=kw=>hdrs.findIndex(h=>h===normAcc(kw)||h.includes(normAcc(kw)));
      const iE=ci('NOME'),iC=ci('NOME COMPLETO'),iF=ci('FUNCAO');
      const iTC=ci('CORP'),iTP=ci('PESSOAL'),iS=ci('STATUS'),iCPF=ci('CPF'),iAdm=ci('ADMISSAO');
      let cntMot=0, cntAux=0, cntSemTel=0, cntPulados=0;
      for(let i=1;i<raw.length;i++){
        const r=raw[i];
        if(!r||!r[iE])continue;
        // Filtro de status: importar SOMENTE ativos. Pular Desligado, Transferido, Inativo, etc.
        const stRaw=String(r[iS]||'').trim();
        if(stRaw && stRaw.toLowerCase()!=='ativo'){ cntPulados++; continue; }
        const nE=String(r[iE]||'').trim();
        const nC=String(r[iC]||'').trim();
        const fnRaw=normAcc(String(r[iF]||''));
        // Filtro de função: só importar pessoal de operação (motoristas + auxiliares de transporte)
        // Ignora Líder Logística, Encarregado, etc.
        if(!fnRaw.includes('MOTORISTA') && !fnRaw.includes('AUXILIAR DE TRANSPORTE')){
          cntPulados++; continue;
        }
        const fn=fnRaw.includes('MOTORISTA')?'MOTORISTA':'AUXILIAR';
        const tC=cleanPhone(iTC>=0?r[iTC]:'');
        const tP=cleanPhone(iTP>=0?r[iTP]:'');
        const tel=tP||tC;
        if(!tel) cntSemTel++;
        const rec={nome_escala:nE,nome_ponto:nC,funcao:fn,cpf:String(r[iCPF]||'').trim(),admissao:String(r[iAdm]||'').trim(),tel_corp:tC,telefone:tel,obs:String(r[iS]||'').trim()};
        const store=fn==='MOTORISTA'?'motoristas':'auxiliares';
        const pk=nE||nC;if(!pk)continue;
        cadData[store][pk]=rec;
        await savePh(nE,nC,tel,fn);
        imported++;
        if(fn==='MOTORISTA') cntMot++; else cntAux++;
      }
      const okM = cadSave('motoristas');
      const okA = cadSave('auxiliares');
      console.log('[Import Funcionários] Total processado:', imported,
                  '| Motoristas:', cntMot, '| Auxiliares:', cntAux,
                  '| Sem tel:', cntSemTel, '| Pulados:', cntPulados,
                  '| Em memória:', Object.keys(cadData.motoristas).length, Object.keys(cadData.auxiliares).length);
      // Sanity-check pós-gravação
      const checkM = lsGet('cad_motoristas',{});
      const checkA = lsGet('cad_auxiliares',{});
      const savedM = Object.keys(checkM).length, savedA = Object.keys(checkA).length;
      renderCadTable(type);renderPhonesTable().catch(()=>{});
      if(savedM<cntMot || savedA<cntAux || !okM || !okA){
        alert(
          '⚠ Importação parcial — alguns registros podem não ter sido salvos.\n\n' +
          '• Processados: '+cntMot+' motoristas + '+cntAux+' auxiliares\n' +
          '• Salvos no navegador: '+savedM+' motoristas + '+savedA+' auxiliares\n\n' +
          'Veja o Console (F12) para detalhes do erro.'
        );
      } else {
        alert(
          '✓ Importação concluída!\n\n' +
          '• '+cntMot+' motoristas\n' +
          '• '+cntAux+' auxiliares\n' +
          '• '+cntSemTel+' sem telefone (preencher manualmente)\n' +
          '• '+cntPulados+' ignorados (desligados, transferidos ou função administrativa)\n\n' +
          'Telefones sincronizados para WhatsApp.'
        );
      }
      return;
    }

    // ── FORMATO B1: Export Veículos do sistema (sheet "Veiculos" com colunas placa/marca/modelo/tipo/situacao/filial) ──
    {
      const snVeic = wb.SheetNames.find(s=>normAcc(s.trim())==='VEICULOS' || normAcc(s.trim())==='VEICULO');
      if(snVeic && type==='veiculos'){
        const raw=XLSX.utils.sheet_to_json(wb.Sheets[snVeic],{header:1,defval:'',raw:false});
        if(raw.length>1){
          const hdrs=raw[0].map(v=>normAcc(String(v||'').trim()));
          // Must have at least 'placa' column to be this format
          if(hdrs.includes('PLACA')){
            const ci=kw=>hdrs.findIndex(h=>h===normAcc(kw));
            const iPlaca=ci('PLACA'), iMarca=ci('MARCA'), iModelo=ci('MODELO'),
                  iTipo=ci('TIPO'), iSit=ci('SITUACAO'), iFil=ci('FILIAL'),
                  iVolT=ci('VOLUME_TANQUE'), iPbt=ci('PBT'), iCor=ci('COR'),
                  iAnoF=ci('ANOFAB'), iEixos=ci('EIXOS');
            let cntInativos=0, cntSemPlaca=0;
            for(let i=1;i<raw.length;i++){
              const r=raw[i]; if(!r) continue;
              const placa=String(r[iPlaca]||'').trim().toUpperCase();
              if(!placa){ cntSemPlaca++; continue; }
              const sit=String(r[iSit]||'').trim().toLowerCase();
              if(sit && sit!=='ativo'){ cntInativos++; continue; }
              const marca=String(r[iMarca]||'').trim();
              const modelo=String(r[iModelo]||'').trim();
              const tipo=String(r[iTipo]||'').trim();
              const filial=String(r[iFil]||'').trim();
              const pbt=iPbt>=0?String(r[iPbt]||'').trim():'';
              const volT=iVolT>=0?String(r[iVolT]||'').trim():'';
              const obsBits=[];
              if(iAnoF>=0 && r[iAnoF]) obsBits.push('Ano: '+r[iAnoF]);
              if(iEixos>=0 && r[iEixos]) obsBits.push('Eixos: '+r[iEixos]);
              if(iCor>=0 && r[iCor]) obsBits.push('Cor: '+r[iCor]);
              if(volT) obsBits.push('Tanque: '+volT+'L');
              cadData.veiculos[placa]={
                placa,
                marca,
                modelo,
                tipo,
                filial,
                capacidade:pbt,
                rota_padrao:'',
                obs:obsBits.join(' · ')
              };
              imported++;
            }
            const okV = cadSave('veiculos');
            const savedV = Object.keys(lsGet('cad_veiculos',{})).length;
            console.log('[Import Veículos] Processados:', imported, '| Inativos:', cntInativos, '| Sem placa:', cntSemPlaca, '| Salvos:', savedV);
            renderCadTable('veiculos');
            if(!okV || savedV<imported){
              alert('⚠ Importação parcial — '+savedV+' de '+imported+' salvos. Veja Console (F12).');
            } else {
              alert(
                '✓ Importação de veículos concluída!\n\n' +
                '• '+imported+' veículos ativos importados\n' +
                (cntInativos?'• '+cntInativos+' inativos ignorados\n':'') +
                (cntSemPlaca?'• '+cntSemPlaca+' linhas sem placa ignoradas\n':'')
              );
            }
            return;
          }
        }
      }
    }

    // ── FORMATO B: Roteiro SP (tem abas MOTORISTAS / AUXILIAR com header em row5) ──
    if(isRoteiro&&(type==='motoristas'||type==='auxiliares')){
      const tgt=type==='motoristas'?['MOTORISTAS','MOTORISTA']:['AUXILIAR','AUXILIARES'];
      const sn=wb.SheetNames.find(s=>tgt.some(t=>s.trim().toUpperCase()===t));
      if(!sn){alert('Aba '+tgt[0]+' não encontrada no Roteiro.');return;}
      const raw=XLSX.utils.sheet_to_json(wb.Sheets[sn],{header:1,defval:'',raw:false});
      let hdr=0;
      for(let i=0;i<Math.min(raw.length,8);i++){
        if(raw[i].map(v=>String(v||'').toUpperCase()).some(h=>h.includes('NOME COMPLETO'))){hdr=i;break;}
      }
      const hdrs=raw[hdr].map(v=>String(v||'').trim().toUpperCase());
      const ci=kw=>hdrs.findIndex(h=>h===kw||h.includes(kw));
      const iE=type==='motoristas'?ci('MOTORISTA'):ci('NOME');
      const iC=ci('NOME COMPLETO'),iTC=ci('CORPORATIVO'),iTP=ci('PESSOAL');
      for(let i=hdr+1;i<raw.length;i++){
        const r=raw[i];
        const nE=String(r[iE]||'').trim();const nC=String(r[iC]||'').trim();
        if(!nE&&!nC)continue;
        const tC=cleanPhone(iTC>=0?r[iTC]:'');const tP=cleanPhone(iTP>=0?r[iTP]:'');
        const tel=tP||tC;
        const fn=type==='motoristas'?'MOTORISTA':'AUXILIAR';
        cadData[type][nE||nC]={nome_escala:nE,nome_ponto:nC,funcao:fn,cpf:String(r[ci('CPF')]||'').trim(),admissao:'',tel_corp:tC,telefone:tel,obs:''};
        await savePh(nE,nC,tel,fn);imported++;
      }
      cadSave(type);renderCadTable(type);renderPhonesTable().catch(()=>{});
      alert('✓ '+imported+' '+type+' importados do Roteiro SP! Telefones sincronizados.');
      return;
    }

    // ── FORMATO C: CONTROLE_DE_JORNADA.xlsx ───────────────────
    const tMap={motoristas:['MOTORISTA','MOTORISTAS'],auxiliares:['AUXILIAR','AUXILIARES'],veiculos:['PLACA','PLACAS'],cidades:['CIDADE','CIDADES','ROTA']};
    let ws=null;
    for(const sn of wb.SheetNames){if(tMap[type].some(t=>sn.trim().toUpperCase()===t)){ws=wb.Sheets[sn];break;}}
    if(!ws){for(const sn of wb.SheetNames){if(tMap[type].some(t=>sn.trim().toUpperCase().includes(t))){ws=wb.Sheets[sn];break;}}}
    if(!ws){alert('Aba não encontrada. Disponíveis: '+wb.SheetNames.join(', '));return;}
    const raw=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});
    // Detect header row: look for key column names
    let hdr=0;
    const hdrKeys={
      motoristas:['NOME COMPLETO','MOTORISTA'],
      auxiliares:['NOME COMPLETO','AUXILIAR','NOME'],
      veiculos:['PLACA','SEQ CAMIN','QT'],
      cidades:['ROTAS','CIDADES','CIDADE']
    };
    const targetKeys=hdrKeys[type]||['NOME'];
    for(let i=0;i<Math.min(raw.length,8);i++){
      const u=raw[i].map(v=>normAcc(String(v||'')));
      if(targetKeys.some(k=>u.some(h=>h===normAcc(k)||h.includes(normAcc(k))))){hdr=i;break;}
    }
    const hdrs=raw[hdr].map(v=>normAcc(String(v||'')));
    const ci=kw=>hdrs.findIndex(h=>h===normAcc(kw)||h.includes(normAcc(kw)));
    for(let i=hdr+1;i<raw.length;i++){
      const r=raw[i];if(!r||r.every(v=>!v))continue;
      if(type==='motoristas'){
        const nE=String(r[ci('MOTORISTA')]||'').trim();const nC=String(r[ci('NOME COMPLETO')]||'').trim();
        const tC=cleanPhone(ci('CORPORATIVO')>=0?r[ci('CORPORATIVO')]:'');const tP=cleanPhone(ci('PESSOAL')>=0?r[ci('PESSOAL')]:'');
        const tel=tP||tC;const pk=nE||nC;if(!pk)continue;
        cadData[type][pk]={nome_escala:nE,nome_ponto:nC,funcao:'MOTORISTA',cpf:String(r[ci('CPF')]||'').trim(),admissao:'',tel_corp:tC,telefone:tel,obs:''};
        await savePh(nE,nC,tel,'MOTORISTA');imported++;
      }else if(type==='auxiliares'){
        const nE=String(r[ci('NOME')]||r[ci('AUXILIAR')]||'').trim();const nC=String(r[ci('NOME COMPLETO')]||'').trim();
        const tel=cleanPhone(ci('PESSOAL')>=0?r[ci('PESSOAL')]:'');const pk=nE||nC;if(!pk)continue;
        cadData[type][pk]={nome_escala:nE,nome_ponto:nC,funcao:'AUXILIAR',cpf:String(r[ci('CPF')]||'').trim(),admissao:'',tel_corp:'',telefone:tel,obs:''};
        await savePh(nE,nC,tel,'AUXILIAR');imported++;
      }else if(type==='veiculos'){
        // PLACAS sheet: value is 'DIO-5881 - SPRINTER' in PLACA column
        const rawPlaca=String(r[ci('PLACA')]||'').trim();
        if(!rawPlaca||rawPlaca==='PLACA'||rawPlaca==='QT') continue;
        let placa=rawPlaca, modelo='';
        if(rawPlaca.includes(' - ')){const parts=rawPlaca.split(' - ');placa=parts[0].trim();modelo=parts.slice(1).join(' - ').trim();}
        const modeloCol=ci('MODELO')>=0?String(r[ci('MODELO')]||'').trim():'';
        if(modeloCol) modelo=modeloCol;
        if(!placa) continue;
        cadData[type][placa]={placa,modelo,capacidade:String(r[ci('CAPAC')]||r[ci('KG')]||'').trim(),tipo:String(r[ci('TIPO')]||'').trim(),rota_padrao:String(r[ci('ROTA')]||'').trim(),obs:''};
        imported++;
      }else if(type==='cidades'){
        // ROTAS sheet: col0='RT 01', col4='IGUAPE / ILHA COMPRIDA'
        const rawRota=String(r[0]||'').trim();
        if(!rawRota||rawRota==='ROTAS'||rawRota==='DIA') continue;
        const rtMatch=rawRota.match(/RT\s*0*(\d+)/i);
        if(!rtMatch) continue; // skip non-route rows
        const rotaNum=rtMatch[1];
        // City is in the column named CIDADES
        const cidIdx=hdrs.findIndex(h=>h==='CIDADES'||h==='CIDADE');
        const cidade=cidIdx>=0?String(r[cidIdx]||'').trim():'';
        if(!cidade) continue;
        cadData[type][rotaNum]={rota:rotaNum,cidade,uf:'',obs:''};
        imported++;
      }
    }
    cadSave(type);renderCadTable(type);renderPhonesTable().catch(()=>{});
    alert('✓ '+imported+' registro(s) importados!'+(type==='motoristas'||type==='auxiliares'?' Telefones sincronizados.':''));
  };
  inp.click();
}

// ── PHONES DIRECTORY ──────────────────────────────────────
async function renderPhonesTable(){
  const phones=await dbGetAllPhones();
  const q=(document.getElementById('phones-search')?.value||'').toLowerCase();
  const filtered=q?phones.filter(p=>p.nome.toLowerCase().includes(q)||p.tel.includes(q)):phones;
  // Deduplicate: if same tel exists under multiple names, keep the longer (complete) name
  const telSeen = {};
  const deduped = [];
  filtered.forEach(p=>{
    const t = p.tel||'';
    if(!t){deduped.push(p);return;}
    if(!telSeen[t]||p.nome.length>telSeen[t].nome.length){
      telSeen[t]={...p, idx:deduped.length};
      deduped.push(p);
    } else {
      // Replace the shorter name entry
      const old=deduped.findIndex(x=>x.tel===t&&x.nome.length<p.nome.length);
      if(old>=0) deduped[old]=p;
    }
  });
  const filteredDedup = deduped;
  filtered.sort((a,b)=>a.nome.localeCompare(b.nome));
  // Use deduped for display
  const displayList = filteredDedup.sort((a,b)=>a.nome.localeCompare(b.nome));
  const cnt=document.getElementById('phones-count');
  const uniqueTels = new Set(phones.map(p=>p.tel).filter(Boolean)).size;
  if(cnt)cnt.textContent=`${phones.length} cadastrado(s) · ${uniqueTels} números únicos`;
  const tbody=document.getElementById('phones-tbody');
  if(!tbody)return;
  if(!filtered.length){
    tbody.innerHTML='<tr><td colspan="4" style="padding:20px;text-align:center;color:var(--text3)">Nenhum resultado</td></tr>';
    return;
  }
  tbody.innerHTML=displayList.map(p=>`
    <tr style="border-bottom:0.5px solid var(--border)">
      <td style="padding:8px 12px;font-size:12.5px;font-weight:500">${esc(p.nome)}</td>
      <td style="padding:8px 12px;font-size:12.5px;font-family:'JetBrains Mono',monospace">${esc(p.tel)}</td>
      <td style="padding:8px 12px;font-size:12px;color:var(--text3)">${esc(p.obs||'')}</td>
      <td style="padding:8px 10px">
        <div style="display:flex;gap:5px">
          <button onclick="openWaDirect('${esc(p.nome)}','${esc(p.tel)}')" style="padding:4px 8px;border-radius:6px;border:none;background:#25D366;color:#fff;font-size:11px;font-weight:600;cursor:pointer">WA</button>
          <button onclick="editPhone('${esc(p.nome)}')" style="padding:4px 8px;border-radius:6px;border:1px solid var(--border);background:var(--bg3);color:var(--text2);font-size:11px;cursor:pointer">✎</button>
          <button onclick="deletePhone('${esc(p.nome)}')" style="padding:4px 8px;border-radius:6px;border:1px solid var(--red-b);background:var(--red-l);color:var(--red);font-size:11px;cursor:pointer">✕</button>
        </div>
      </td>
    </tr>`).join('');
}

function openAddPhoneModal(){
  document.getElementById('phone-nome-inp').value='';
  const dispEl2=document.getElementById('phone-nome-display');
  if(dispEl2) dispEl2.textContent='(novo cadastro)';
  document.getElementById('phone-tel-inp').value='';
  document.getElementById('phone-obs-inp').value='';
  document.getElementById('phone-modal-title').textContent='Adicionar WhatsApp';
  document.getElementById('phone-modal-sub').textContent='Cadastre o número de um colaborador';
  phoneModalRow=null;
  document.getElementById('phone-modal-overlay').classList.add('open');
  setTimeout(()=>document.getElementById('phone-nome-inp').focus(),100);
}

async function editPhone(nome){
  const p=await dbGetPhone(nome);if(!p)return;
  document.getElementById('phone-nome-inp').value=p.nome;
  document.getElementById('phone-nome-inp').removeAttribute('readonly');
  document.getElementById('phone-tel-inp').value=p.tel;
  document.getElementById('phone-obs-inp').value=p.obs||'';
  document.getElementById('phone-modal-title').textContent='Editar WhatsApp';
  document.getElementById('phone-modal-sub').textContent=p.nome;
  phoneModalRow=null;
  document.getElementById('phone-modal-overlay').classList.add('open');
}

async function deletePhone(nome){
  if(!confirm(`Remover telefone de ${nome}?`))return;
  if(db){const tx=db.transaction('phones','readwrite');tx.objectStore('phones').delete(nome);}
  else{const p=lsGet('phones',{});delete p[nome];lsSet('phones',p);}
  renderPhonesTable();
  renderS4Table();
}

function openWaDirect(nome,tel){
  openWhatsApp(nome,tel,null);
}

async function exportPhonesJSON(){
  const phones=await dbGetAllPhones();
  const blob=new Blob([JSON.stringify({phones,exported:new Date().toISOString()},null,2)],{type:'application/json'});
  dlBlob(blob,'marquespan_phones.json');
}
async function importPhonesJSON(){
  const inp=document.createElement('input');inp.type='file';inp.accept='application/json';inp.onchange=async e=>{
    const f=e.target.files[0];if(!f)return;
    const reader=new FileReader();reader.onload=async ev=>{
      try{
        const obj=JSON.parse(ev.target.result);
        if(!obj.phones)return alert('JSON inválido.');
        if(!confirm(`Importar ${obj.phones.length} telefone(s)?`))return;
        for(const p of obj.phones)await dbSavePhone(p.nome,p.tel,p.obs||'');
        renderPhonesTable();alert('Importado com sucesso!');
      }catch(err){alert('Erro ao ler JSON.');}
    };reader.readAsText(f);
  };inp.click();
}

// ── Importar telefones de planilha XLSX/CSV ──────────────────
async function importPhonesXLSX(){
  const inp=document.createElement('input');
  inp.type='file';
  inp.accept='.xlsx,.xls,.csv';
  inp.onchange=async e=>{
    const f=e.target.files[0]; if(!f) return;
    try{
      const buf=await f.arrayBuffer();
      const wb=XLSX.read(buf,{type:'array',raw:false,cellDates:false});

      const cleanPhone=v=>{
        if(!v||v==='-') return '';
        const s=String(v).split(/[,\/;]/)[0].trim();
        const d=s.replace(/[^0-9]/g,'');
        return d.length>=8?d:'';
      };
      const normHdr=v=>String(v||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim().toUpperCase();

      let imported=0, semTel=0;

      for(const sn of wb.SheetNames){
        const raw=XLSX.utils.sheet_to_json(wb.Sheets[sn],{header:1,defval:'',raw:false});
        if(!raw.length) continue;

        // Encontrar linha de cabeçalho — primeira linha que contenha algo parecido com NOME
        let hdrIdx=-1;
        for(let i=0;i<Math.min(raw.length,10);i++){
          const row=raw[i].map(normHdr);
          if(row.some(h=>h==='NOME'||h==='NOME COMPLETO'||h==='COLABORADOR'||h==='FUNCIONARIO'||h.includes('MOTORISTA')||h.includes('AUXILIAR'))){
            hdrIdx=i; break;
          }
        }
        if(hdrIdx<0) continue;

        const hdrs=raw[hdrIdx].map(normHdr);

        // Coluna do nome (preferência: NOME COMPLETO)
        const nameKeywords=['NOME COMPLETO','NOME','COLABORADOR','FUNCIONARIO','MOTORISTA','AUXILIAR'];
        let iName=-1;
        for(const k of nameKeywords){
          iName=hdrs.findIndex(h=>h===k);
          if(iName<0) iName=hdrs.findIndex(h=>h.includes(k));
          if(iName>=0) break;
        }
        // Coluna alternativa de nome (apelido / escala / ponto)
        let iAlt=hdrs.findIndex((h,i)=>i!==iName && (h==='NOME'||h==='APELIDO'||h.includes('ESCALA')||h.includes('PONTO')));

        // Colunas de telefone (preferência: PESSOAL > CELULAR > WHATSAPP > TELEFONE > CORPORATIVO)
        const telKeywords=['PESSOAL','CELULAR','WHATSAPP','TELEFONE PESSOAL','TELEFONE','TEL','FONE','CORPORATIVO'];
        const telCols=[];
        for(const k of telKeywords){
          hdrs.forEach((h,i)=>{ if((h===k||h.includes(k))&&!telCols.includes(i)) telCols.push(i); });
        }
        if(iName<0||!telCols.length) continue;

        for(let r=hdrIdx+1;r<raw.length;r++){
          const row=raw[r]; if(!row) continue;
          const nome=String(row[iName]||'').trim();
          const alt =iAlt>=0?String(row[iAlt]||'').trim():'';
          if(!nome&&!alt) continue;
          let tel='';
          for(const ci of telCols){ tel=cleanPhone(row[ci]); if(tel) break; }
          if(!tel){ semTel++; continue; }

          if(nome) await dbSavePhone(nome,tel,'').catch(()=>{});
          if(alt && alt!==nome) await dbSavePhone(alt,tel,'').catch(()=>{});
          imported++;
        }
      }

      await renderPhonesTable();
      if(typeof renderS4Table==='function' && s4Rows.length) renderS4Table();

      alert(
        '✓ Importação concluída!\n\n'+
        '• '+imported+' telefone(s) salvos\n'+
        (semTel?('• '+semTel+' linhas sem telefone válido (ignoradas)\n'):'')+
        '\nOs números já estão disponíveis para envio via WhatsApp na tabela do 4º Passo.'
      );
    }catch(err){
      console.error(err);
      alert('Erro ao ler a planilha: '+err.message);
    }
  };
  inp.click();
}

