async function updateRelStats(){
  const tot=document.getElementById('rel-total');
  const inf=document.getElementById('rel-inf');
  const ok=document.getElementById('rel-ok');
  const ac=document.getElementById('rel-acoes');
  if(s4Rows.length){
    const infCount=s4Rows.filter(r=>r.obs&&r.obs!=='OK'&&r.obs!=='SEM REGISTRO').length;
    const okCount=s4Rows.filter(r=>r.obs==='OK').length;
    if(tot)tot.textContent=s4Rows.length;
    if(inf)inf.textContent=infCount;
    if(ok)ok.textContent=okCount;
  }
  dbGetAll('actions').then(acts=>{
    if(ac)ac.textContent=acts.length;
  }).catch(()=>{});
}

async function refreshDashboard(){
  const acts=await dbGetAll('actions');
  document.getElementById('d-acoes').textContent=acts.length;

  if(s4Rows.length){
    document.getElementById('d-func').textContent=s4Rows.length;
    const inf=s4Rows.filter(r=>checkIssues(r.saida,r.entrada,r.interj).length>0).length;
    document.getElementById('d-inf').textContent=inf;
    const ij=s4Rows.filter(r=>checkIssues(r.saida,r.entrada,r.interj).find(i=>i.type==='IJ_CURTA')).length;
    document.getElementById('d-ij').textContent=ij;
  }else if(s1Rows.length){
    document.getElementById('d-func').textContent=[...new Set(s1Rows.map(r=>r.nome))].length;
    document.getElementById('d-inf').textContent=s1Rows.filter(r=>r.flags.length>0).length;
    document.getElementById('d-ij').textContent=s1Rows.filter(r=>r.flags.includes('IJ')).length;
  }

  // Recent actions
  const recCont=document.getElementById('dash-recent-actions');
  if(acts.length){
    recCont.innerHTML=acts.slice().reverse().slice(0,5).map(a=>`<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border)"><div style="width:8px;height:8px;border-radius:50%;background:${a.acao.includes('SUSPENSÃO')?'var(--red)':a.acao.includes('ESCRITA')?'var(--red)':a.acao.includes('VERBAL')?'var(--orange)':'var(--blue)'};flex-shrink:0"></div><div style="flex:1"><div style="font-size:12px;font-weight:600">${esc(a.nome||'')} <span style="color:var(--text3);font-weight:400">${esc(a.placa||'')}</span></div><div style="font-size:11px;color:var(--text3)">${esc(a.data_acao||a.timestamp||'')} — <strong>${esc(a.acao)}</strong></div></div></div>`).join('');
  }else{recCont.innerHTML='<div style="font-size:13px;color:var(--text3);text-align:center;padding:16px">Nenhuma ação registrada</div>';}
}

