function setStepDone(n){
  const numEl=document.getElementById('pn'+n);
  const stEl=document.getElementById('ps'+n+'-st');
  const scEl=document.getElementById('sc'+n);
  if(numEl){numEl.classList.remove('a','p');numEl.classList.add('d');}
  if(scEl){scEl.classList.add('done');scEl.textContent='✓';}
  if(stEl){stEl.className='ps-status ok';const msgs={1:'Interjornada calculada',2:'Controle preenchido',3:'Resumos gerados',4:'Pronto para análise'};stEl.textContent=msgs[n]||'Concluído';}
  // Activate next step
  const next=n+1;
  const nxEl=document.getElementById('pn'+next);
  const nxSt=document.getElementById('ps'+next+'-st');
  const nxSc=document.getElementById('sc'+next);
  if(nxEl&&nxEl.classList.contains('p')){nxEl.classList.remove('p');nxEl.classList.add('a');}
  if(nxSt&&nxSt.classList.contains('pend')){nxSt.className='ps-status act';nxSt.textContent='Pronto para iniciar';}
  if(nxSc)nxSc.classList.add('active');
}

// ═══════════════════════════════════════════════════════
//  DATE UTILS
// ═══════════════════════════════════════════════════════
function parseDateStr(s){
  const m=String(s).match(/(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2,4})/);
  if(!m)return null;
  const d=parseInt(m[1]),mo=parseInt(m[2]),y=m[3].length===2?2000+parseInt(m[3]):parseInt(m[3]);
  const dt=new Date(y,mo-1,d);
  return isNaN(dt)?null:dt;
}
function fmtDate(dt){return`${String(dt.getDate()).padStart(2,'0')}/${String(dt.getMonth()+1).padStart(2,'0')}/${dt.getFullYear()}`;}
function fmtAba(dt){return`${String(dt.getDate()).padStart(2,'0')}.${String(dt.getMonth()+1).padStart(2,'0')}.${String(dt.getFullYear()).slice(-2)}`;}
function extractDate(name){const m=(name||'').match(/(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2,4})/);if(!m)return'';const y=m[3].length===2?'20'+m[3]:m[3];return m[1].padStart(2,'0')+'/'+m[2].padStart(2,'0')+'/'+y;}

// ═══════════════════════════════════════════════════════
//  DOWNLOAD HELPERS
// ═══════════════════════════════════════════════════════
function dl(bin,name){const blob=new Blob([bin],{type:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'});dlBlob(blob,name);}
function dlText(text,name){const blob=new Blob(['\uFEFF'+text],{type:'text/csv;charset=utf-8'});dlBlob(blob,name);}
function dlBlob(blob,name){const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();URL.revokeObjectURL(a.href);}

